INSERT INTO public.resultados VALUES ('353e4243-247b-4d35-b14e-142a779f3a72', '1f6467ee-45f8-42ba-84e6-74e0db536450', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Saliendo con amigos, en actividades grupales o ayudando a otros.", "3": "Pido opiniones, converso con mi equipo y buscamos una solución juntos.", "4": "En campo, construcciones, plantas industriales o al aire libre.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Me adapto fácilmente si eso ayuda a que el grupo funcione mejor.", "11": "Para que les ayude a organizar un evento, fiesta o vender algo.", "12": "Diseñar y construir un puente o edificio moderno para tu ciudad.", "13": "Pidiéndole a alguien que ya sepa que me explique paso a paso.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, jhon! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y ofrecerte algunas ideas para tu futuro en nuestra querida Piura.", "perfil": "jhon, tu perfil es realmente enriquecedor y muestra una combinaci\u00f3n poderosa de habilidades e intereses. Por un lado, tienes una clara inclinaci\u00f3n hacia las **ciencias exactas** como las Matem\u00e1ticas, F\u00edsica y Qu\u00edmica (Pregunta 1), y un fuerte deseo de **crear y construir** infraestructuras tangibles, como puentes y edificios modernos (Pregunta 12). Te sientes c\u00f3modo trabajando **en campo, en construcciones o plantas industriales** (Pregunta 4), y manejando **manuales de maquinaria, planos arquitect\u00f3nicos o herramientas de taller** (Pregunta 7), lo que indica una mente pr\u00e1ctica y orientada a la ingenier\u00eda.\n\nPor otro lado, eres una persona profundamente **social, emp\u00e1tica y orientada al servicio** (Preguntas 2, 5, 6, 8, 9, 10, 14). Disfrutas **ayudando a otros**, siendo un **conciliador** en tu equipo y te interesan temas de **salud mental, derechos humanos y causas sociales** (Pregunta 6). Valoras enormemente sentir que tu trabajo **mejora la vida de tu comunidad** (Pregunta 9). Eres **comunicativo**, disfrutas el **trabajo en equipo** (Pregunta 14) y te adaptas f\u00e1cilmente para el bien del grupo (Pregunta 10). Tu forma de aprender es pr\u00e1ctica, pidiendo explicaciones paso a paso (Pregunta 13). Esta combinaci\u00f3n de una mente anal\u00edtica y pr\u00e1ctica con un gran coraz\u00f3n social y colaborativo es tu mayor fortaleza.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda Civil (Universidad Nacional de Piura - UNP, Universidad de Piura - UDEP, Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera te permitir\u00eda aplicar tu fuerte inter\u00e9s en Matem\u00e1ticas, F\u00edsica y Qu\u00edmica (P1) para dise\u00f1ar y construir infraestructuras como puentes o edificios modernos para tu ciudad (P12). Trabajar\u00edas en campo y construcciones (P4), utilizando planos arquitect\u00f3nicos y herramientas (P7), lo que se alinea con tu preferencia por lo pr\u00e1ctico y tangible. Adem\u00e1s, cumplir\u00edas con tu deseo de que tu trabajo mejore la vida de tu comunidad (P9) y tu capacidad para trabajar en equipo (P3, P10, P14) ser\u00eda fundamental."}, {"titulo": "Psicolog\u00eda (Universidad Nacional de Piura - UNP, Universidad de Piura - UDEP, Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Tu marcada empat\u00eda, comunicaci\u00f3n y disfrute por ayudar a otros (P2, P14), junto con tu inter\u00e9s en temas de salud mental, derechos humanos y causas sociales (P6), encajan perfectamente aqu\u00ed. Ser\u00edas un conciliador (P5) que busca soluciones en equipo (P3), y tu deseo de asistir a adultos mayores o dar clases de refuerzo (P8) se alinea directamente con el servicio a la comunidad (P9) y la mejora de la vida de las personas."}, {"titulo": "Tecnolog\u00eda en Construcci\u00f3n Civil o Mantenimiento de Maquinaria Pesada (SENATI)", "descripcion": "Si buscas una formaci\u00f3n m\u00e1s t\u00e9cnica y pr\u00e1ctica con una r\u00e1pida inserci\u00f3n laboral, estas opciones en SENATI son ideales. Te permitir\u00edan trabajar directamente en campo, construcciones o plantas industriales (P4), utilizando herramientas de taller y manuales de maquinaria (P7). Es una v\u00eda directa para contribuir tangiblemente a tu comunidad (P9) y aplicar tu gusto por el aprendizaje paso a paso (P13), con un fuerte componente de trabajo en equipo (P3, P10, P14) en proyectos concretos."}], "conclusiones": "jhon, tienes un potencial incre\u00edble y una valiosa combinaci\u00f3n de habilidades t\u00e9cnicas y humanas. Reflexiona sobre estas opciones y c\u00f3mo cada una te permitir\u00eda aplicar tus talentos y cumplir tu deseo de servir a tu comunidad en Piura. \u00a1El camino que elijas estar\u00e1 lleno de oportunidades para crecer y dejar tu huella!"}', '2026-06-22 09:01:46.182886', NULL);
INSERT INTO public.resultados VALUES ('b20b533d-0f01-48d2-afdd-867c93d4bfc9', '769c8da3-4975-4ac6-a940-40abb85124fd', 1, '{"1": "Psicología, Tutoría o Educación Física (Trabajar con personas y bienestar).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El líder que expone, reparte los temas y organiza los tiempos.", "6": "Descubrimientos científicos, avances médicos o documentales de naturaleza.", "7": "Un microscopio, instrumentos de medición o software de datos.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para pedirme un consejo personal o porque sé escuchar muy bien.", "12": "Encontrar la cura para una enfermedad compleja.", "13": "Leyendo el manual completo antes de tocar cualquier pieza.", "14": "Soy una persona creativa, original y muy conectada con mis emociones."}', '{"saludo": "\u00a1Hola, LUCIA ANTHUANETH!", "perfil": "Hubo un error al procesar tu an\u00e1lisis con la IA: 503 UNAVAILABLE. {''error'': {''code'': 503, ''message'': ''This model is currently experiencing high demand. Spikes in demand are usually temporary. Please try again later.'', ''status'': ''UNAVAILABLE''}}", "carreras_sugeridas": [], "conclusiones": "Por favor, intenta realizar el test m\u00e1s tarde."}', '2026-06-22 10:00:31.534545', NULL);
INSERT INTO public.resultados VALUES ('93f5d8f7-9f9a-49c5-a1f1-bfe6e5ee50ab', '1f6467ee-45f8-42ba-84e6-74e0db536450', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El que diseña las diapositivas, hace la carátula y le da el toque visual.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Ir al campo a construir casas, limpiar playas o plantar árboles.", "9": "La independencia: tener libertad para expresar mis ideas sin horarios estrictos.", "10": "Me encantan; prefiero tener instrucciones claras, orden y saber qué esperar.", "11": "Para pedirme un consejo personal o porque sé escuchar muy bien.", "12": "Escribir un libro o dirigir una película que impacte a millones.", "13": "Empezando a armarlo directamente, aprendiendo mediante la práctica y el error.", "14": "Soy una persona creativa, original y muy conectada con mis emociones."}', '{"saludo": "\u00a1Hola, jhon!", "perfil": "Hubo un error al procesar tu an\u00e1lisis con la IA: 503 UNAVAILABLE. {''error'': {''code'': 503, ''message'': ''This model is currently experiencing high demand. Spikes in demand are usually temporary. Please try again later.'', ''status'': ''UNAVAILABLE''}}", "carreras_sugeridas": [], "conclusiones": "Por favor, intenta realizar el test m\u00e1s tarde."}', '2026-06-22 10:02:55.705211', NULL);
INSERT INTO public.resultados VALUES ('b36dd1be-463c-4617-afb5-203171b1ee2b', '1f6467ee-45f8-42ba-84e6-74e0db536450', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Tomo el liderazgo, organizo a los demás y tomo decisiones rápidas.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Me adapto fácilmente si eso ayuda a que el grupo funcione mejor.", "11": "Para que les ayude a organizar un evento, fiesta o vender algo.", "12": "Diseñar y construir un puente o edificio moderno para tu ciudad.", "13": "Pidiéndole a alguien que ya sepa que me explique paso a paso.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, jhon! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tus respuestas y darte una gu\u00eda para tu futuro profesional aqu\u00ed en Piura.", "perfil": "jhon, tu perfil se destaca por una interesante combinaci\u00f3n de habilidades anal\u00edticas y un fuerte deseo de impacto social. Muestras una clara inclinaci\u00f3n por las ciencias exactas como las Matem\u00e1ticas, la F\u00edsica y la Qu\u00edmica (Pregunta 1), disfrutando de la investigaci\u00f3n y la formulaci\u00f3n de estrategias (Pregunta 2). Eres una persona con iniciativa, liderazgo natural y capacidad para organizar y tomar decisiones r\u00e1pidas (Pregunta 3). Te visualizas en entornos corporativos, bancos o incluso dirigiendo tu propia empresa (Pregunta 4), lo que denota ambici\u00f3n y visi\u00f3n de negocio. Adem\u00e1s, posees una marcada vocaci\u00f3n de servicio y empat\u00eda. Eres el conciliador del grupo, dispuesto a ayudar a los dem\u00e1s y a mantener la armon\u00eda (Pregunta 5). Te interesan causas sociales y de derechos humanos (Pregunta 6), y buscas que tu trabajo mejore la vida de tu comunidad (Pregunta 9). Esta faceta se complementa con tu facilidad para trabajar en equipo, adaptarte y comunicarte eficazmente (Preguntas 10 y 14). Tu inter\u00e9s pr\u00e1ctico se evidencia en la manipulaci\u00f3n de manuales de maquinaria, planos arquitect\u00f3nicos y herramientas de taller (Pregunta 7), y en tu sue\u00f1o de dise\u00f1ar y construir infraestructura moderna para tu ciudad (Pregunta 12), lo que sugiere una mente orientada a la soluci\u00f3n de problemas tangibles con un impacto colectivo.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda Civil (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera es ideal para ti, jhon, ya que combina tu pasi\u00f3n por las Matem\u00e1ticas, la F\u00edsica y las ciencias exactas (Pregunta 1) con tu inter\u00e9s pr\u00e1ctico en planos y herramientas de taller (Pregunta 7). Podr\u00e1s aplicar tu deseo de dise\u00f1ar y construir infraestructura vital como puentes y edificios para tu ciudad (Pregunta 12), generando un impacto directo en la mejora de la vida de tu comunidad (Pregunta 9). Tu capacidad de liderazgo, organizaci\u00f3n y toma de decisiones r\u00e1pidas (Pregunta 3) ser\u00e1 fundamental para gestionar proyectos de gran envergadura y tu empat\u00eda te ayudar\u00e1 a entender las necesidades de los usuarios."}, {"titulo": "Ingenier\u00eda Industrial (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "La Ingenier\u00eda Industrial se alinea con tu perfil estrat\u00e9gico y de liderazgo (Preguntas 2 y 3), as\u00ed como con tu visi\u00f3n de trabajar en entornos corporativos o dirigir tu propia empresa (Pregunta 4). Te permitir\u00e1 optimizar procesos y sistemas, aplicando tus conocimientos de ciencias exactas (Pregunta 1) para mejorar la eficiencia en diversos sectores. Tu deseo de que tu trabajo mejore la vida de tu comunidad (Pregunta 9) puede materializarse a trav\u00e9s del dise\u00f1o de sistemas m\u00e1s justos y productivos, y tu habilidad para organizar eventos o vender (Pregunta 11) ser\u00e1 clave en la gesti\u00f3n de proyectos y la implementaci\u00f3n de soluciones."}, {"titulo": "Administraci\u00f3n de Empresas (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV / SENATI - carreras t\u00e9cnicas de gesti\u00f3n)", "descripcion": "Considerando tu habilidad para tomar el liderazgo, organizar y tomar decisiones r\u00e1pidas (Pregunta 3), adem\u00e1s de tu inter\u00e9s en una oficina corporativa, banco o dirigiendo tu propia empresa (Pregunta 4), la Administraci\u00f3n de Empresas es una excelente opci\u00f3n. Podr\u00edas aplicar tu capacidad para organizar eventos o vender (Pregunta 11) y tu esp\u00edritu de servicio (Pregunta 9) para liderar organizaciones con impacto social, o gestionar eficientemente cualquier tipo de empresa, siempre con tu empat\u00eda y habilidad comunicativa (Pregunta 14) como pilares para el trabajo en equipo y la conciliaci\u00f3n (Pregunta 5)."}], "conclusiones": "jhon, tienes un potencial enorme y una visi\u00f3n clara de querer contribuir a tu comunidad. Las carreras que te he sugerido te permitir\u00e1n combinar tu mente anal\u00edtica y estrat\u00e9gica con tu coraz\u00f3n emp\u00e1tico y de servicio. Te animo a investigar m\u00e1s a fondo sobre estas opciones en las prestigiosas instituciones de nuestra querida Piura, como la UNP, UDEP, UCV o SENATI. \u00a1Tu futuro en Piura es prometedor y lleno de oportunidades para que dejes tu huella!"}', '2026-06-22 10:05:54.140008', NULL);
INSERT INTO public.resultados VALUES ('9abeba4b-212d-49cc-bbd3-ba49dabe9917', '872b9144-d457-48b9-b355-1b72b85b73bb', 1, '{"1": "Psicología, Tutoría o Educación Física (Trabajar con personas y bienestar).", "2": "Dibujando, tocando un instrumento, escribiendo o creando contenido.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En campo, construcciones, plantas industriales o al aire libre.", "5": "El que investiga a fondo, recopila la información y revisa que todo tenga sentido.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Una cámara profesional, un lienzo o un programa de diseño gráfico.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para pedirme un consejo personal o porque sé escuchar muy bien.", "12": "Diseñar y construir un puente o edificio moderno para tu ciudad.", "13": "Leyendo el manual completo antes de tocar cualquier pieza.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, ARLEN LISET! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tus respuestas y acompa\u00f1arte en este importante camino hacia tu futuro.", "perfil": "ARLEN LISET, tu perfil revela una combinaci\u00f3n muy interesante de habilidades y pasiones. Por un lado, destacas por tu marcada empat\u00eda, tu capacidad de escucha y tu deseo genuino de trabajar con personas, contribuyendo a su bienestar y a causas sociales. Eres comunicativa y disfrutas del trabajo en equipo, lo que te convierte en una persona colaborativa y confiable. Por otro lado, posees una mente anal\u00edtica y l\u00f3gica; te gusta investigar a fondo, estructurar soluciones paso a paso y buscar la eficiencia, mostrando una gran meticulosidad en todo lo que haces. Tambi\u00e9n tienes una faceta creativa, disfrutando de la expresi\u00f3n art\u00edstica y la creaci\u00f3n de contenido, junto con un claro inter\u00e9s por el dise\u00f1o y la construcci\u00f3n tangible. Adem\u00e1s, demuestras potencial de liderazgo, ambici\u00f3n por dirigir proyectos y una inclinaci\u00f3n hacia la administraci\u00f3n y log\u00edstica, buscando siempre la mejora continua. En resumen, eres una persona emp\u00e1tica, creativa, anal\u00edtica, pr\u00e1ctica, organizada y con aspiraciones de liderazgo.", "carreras_sugeridas": [{"titulo": "Gastronom\u00eda (Instituto Centur / Ceturgh Piura)", "descripcion": "Tu inter\u00e9s expl\u00edcito en Gastronom\u00eda en el Instituto Centur se alinea muy bien con varias de tus fortalezas. Tu creatividad y gusto por ''crear contenido'' o ''dibujar'' se pueden traducir en la innovaci\u00f3n culinaria y la presentaci\u00f3n art\u00edstica de los platos. Tu mente l\u00f3gica y estructurada (''analizo los datos, busco la l\u00f3gica y estructuro una soluci\u00f3n paso a paso'', ''investiga a fondo, recopila la informaci\u00f3n y revisa que todo tenga sentido'', ''leyendo el manual completo'') es ideal para dominar recetas, t\u00e9cnicas culinarias y la gesti\u00f3n de una cocina. Adem\u00e1s, tu habilidad para ''ayudar en la log\u00edstica, administrando las donaciones y el presupuesto'' encaja perfectamente con la gesti\u00f3n de inventarios, costos y administraci\u00f3n de un negocio gastron\u00f3mico. Tu deseo de ''liderazgo y \u00e9xito econ\u00f3mico'' tambi\u00e9n te permitir\u00eda aspirar a dirigir tu propio restaurante o proyectos culinarios de gran envergadura."}, {"titulo": "Ingenier\u00eda Civil o Arquitectura (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Una de tus respuestas m\u00e1s claras fue tu inter\u00e9s en ''dise\u00f1ar y construir un puente o edificio moderno para tu ciudad'', lo cual, combinado con tu preferencia por ''trabajar en campo, construcciones o al aire libre'', apunta fuertemente hacia estas carreras. Tu mente anal\u00edtica, l\u00f3gica y estructurada (''analizo los datos, busco la l\u00f3gica y estructuro una soluci\u00f3n paso a paso'') es fundamental para el dise\u00f1o y c\u00e1lculo de estructuras. Tu meticulosidad (''investiga a fondo, recopila la informaci\u00f3n y revisa que todo tenga sentido'', ''leyendo el manual completo'') es crucial para la seguridad y calidad en la construcci\u00f3n. Adem\u00e1s, tu liderazgo y deseo de ''dirigir proyectos grandes'' encajan con la gesti\u00f3n de obras, y tu creatividad (''dibujando'', ''programa de dise\u00f1o gr\u00e1fico'') ser\u00eda muy valiosa en el dise\u00f1o arquitect\u00f3nico."}, {"titulo": "Psicolog\u00eda o Trabajo Social (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Tu fuerte inclinaci\u00f3n por ''Psicolog\u00eda, Tutor\u00eda o Educaci\u00f3n F\u00edsica (Trabajar con personas y bienestar)'', sumada a tu inter\u00e9s en ''temas de salud mental, derechos humanos, o causas sociales'', y tu habilidad para ''pedir un consejo personal o porque s\u00e9 escuchar muy bien'' y ser ''emp\u00e1tica, comunicativa y disfrutar trabajar en equipo'', son indicadores muy potentes para estas \u00e1reas. En estas carreras, tu capacidad anal\u00edtica y de investigaci\u00f3n (''analizo los datos'', ''investiga a fondo'') te permitir\u00eda comprender problemas complejos y dise\u00f1ar intervenciones efectivas, mientras que tu liderazgo (''dirigir proyectos grandes'') podr\u00eda aplicarse en la gesti\u00f3n de programas sociales o cl\u00ednicas."}], "conclusiones": "ARLEN LISET, es evidente que tienes un futuro prometedor y lleno de posibilidades. Tu pasi\u00f3n por la gastronom\u00eda es una excelente base, y tus m\u00faltiples talentos (tu empat\u00eda, tu mente anal\u00edtica, tu creatividad y tu esp\u00edritu de liderazgo) te dar\u00e1n las herramientas para sobresalir en cualquier camino que elijas. Te animo a seguir investigando sobre estas opciones en Piura, visitar los institutos y universidades, y conversar con profesionales de estos campos. Conf\u00eda en tus habilidades y en tu intuici\u00f3n, \u00a1el \u00e9xito te espera!"}', '2026-06-22 10:15:23.796436', NULL);
INSERT INTO public.resultados VALUES ('414d4f14-8472-43e6-96c7-ab0a3faa7687', '94e70a27-2216-4d76-9449-d282ade38677', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Saliendo con amigos, en actividades grupales o ayudando a otros.", "3": "Tomo el liderazgo, organizo a los demás y tomo decisiones rápidas.", "4": "En un estudio de diseño, teatro, o viajando constantemente.", "5": "El que investiga a fondo, recopila la información y revisa que todo tenga sentido.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Ir al campo a construir casas, limpiar playas o plantar árboles.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Escribir un libro o dirigir una película que impacte a millones.", "13": "Viendo un tutorial en video y fijándome en los detalles visuales.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, PAULITA ANALIA! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo en Piura, analizar tu perfil y acompa\u00f1arte en este importante camino. Tus respuestas nos brindan una visi\u00f3n clara de tus fortalezas y aspiraciones.", "perfil": "PAULITA ANALIA, tus respuestas revelan un perfil muy prometedor y con una clara direcci\u00f3n. Destacas por tu fuerte inclinaci\u00f3n hacia las ciencias exactas como las Matem\u00e1ticas y la F\u00edsica, lo que indica una mente anal\u00edtica y l\u00f3gica. Eres una persona con un marcado liderazgo, te gusta organizar, tomar decisiones r\u00e1pidas y dirigir proyectos, buscando siempre el \u00e9xito y el impacto econ\u00f3mico. Te atrae la investigaci\u00f3n a fondo, el detalle y la b\u00fasqueda de eficiencia en los procesos. Adem\u00e1s, demuestras un gran inter\u00e9s por la tecnolog\u00eda, la maquinaria y la resoluci\u00f3n pr\u00e1ctica de problemas, evidenciando una preferencia por ver resultados tangibles y f\u00edsicos de tu trabajo. Eres pr\u00e1ctica, de acci\u00f3n r\u00e1pida y disfrutas de las actividades grupales, lo que sugiere que te desempe\u00f1as muy bien en entornos colaborativos donde puedes aplicar tu liderazgo y habilidades t\u00e9cnicas.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda Industrial (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera es ideal para ti, Paulita. Combina tu inter\u00e9s por las ciencias exactas y la eficiencia con tu fuerte perfil de liderazgo y organizaci\u00f3n. Te permitir\u00e1 dirigir grandes proyectos, optimizar procesos en diversas industrias y gestionar equipos, lo que encaja perfectamente con tu deseo de \u00e9xito econ\u00f3mico, de proponer formas m\u00e1s eficientes y de ver resultados concretos. Las instituciones de Piura ofrecen programas s\u00f3lidos en esta \u00e1rea."}, {"titulo": "Ingenier\u00eda Mecatr\u00f3nica o Ingenier\u00eda Mec\u00e1nica El\u00e9ctrica (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Tu fascinaci\u00f3n por los motores, la maquinaria, los nuevos celulares, la inteligencia artificial y tu habilidad para arreglar aparatos, junto con tu mente pr\u00e1ctica y tu gusto por los manuales y herramientas de taller, te hacen una excelente candidata para estas ingenier\u00edas. Podr\u00e1s dise\u00f1ar, construir y mantener sistemas complejos, aplicando tus conocimientos de f\u00edsica y matem\u00e1ticas, y tu deseo de innovar y resolver problemas t\u00e9cnicos. Las universidades de Piura cuentan con estas especialidades."}, {"titulo": "Carreras T\u00e9cnicas en Mec\u00e1nica de Producci\u00f3n, Mantenimiento de Maquinaria Pesada o Electr\u00f3nica Industrial (SENATI)", "descripcion": "Si buscas una ruta m\u00e1s pr\u00e1ctica y con r\u00e1pida inserci\u00f3n laboral para lograr tus metas econ\u00f3micas de forma eficiente, SENATI ofrece excelentes programas t\u00e9cnicos. Tu inter\u00e9s por los manuales de maquinaria, las herramientas de taller y la reparaci\u00f3n de aparatos, sumado a tu preferencia por los resultados f\u00edsicos y la acci\u00f3n r\u00e1pida, se alinea perfectamente con estas especialidades. Aqu\u00ed desarrollar\u00edas habilidades t\u00e9cnicas de alta demanda en la regi\u00f3n Piura."}], "conclusiones": "Paulita Analia, tienes un perfil con un gran potencial, combinando habilidades t\u00e9cnicas y anal\u00edticas con una fuerte capacidad de liderazgo y una clara visi\u00f3n de \u00e9xito. En Piura, cuentas con diversas opciones educativas de calidad que te permitir\u00e1n desarrollar estas fortalezas y alcanzar tus sue\u00f1os. Te animo a investigar m\u00e1s a fondo estas carreras, visitar las instituciones y conversar con profesionales de estos campos. \u00a1Estoy seguro de que con tu determinaci\u00f3n, lograr\u00e1s una carrera exitosa y gratificante!"}', '2026-06-22 11:58:46.94066', NULL);
INSERT INTO public.resultados VALUES ('ed6d2631-6822-4ce3-a8d8-5fb238b1b316', '3337c437-59f9-480c-a155-a025848add96', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El que investiga a fondo, recopila la información y revisa que todo tenga sentido.", "6": "Descubrimientos científicos, avances médicos o documentales de naturaleza.", "7": "Un microscopio, instrumentos de medición o software de datos.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El descubrimiento: poder investigar y encontrar verdades o curas.", "10": "Me encantan; prefiero tener instrucciones claras, orden y saber qué esperar.", "11": "Para que les explique tareas difíciles de matemáticas o ciencias.", "12": "Encontrar la cura para una enfermedad compleja.", "13": "Leyendo el manual completo antes de tocar cualquier pieza.", "14": "Soy una persona curiosa, analítica y me gusta llegar al fondo de las cosas."}', '{"saludo": "\u00a1Hola, MATIAS ARIEL! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y acompa\u00f1arte en este importante camino. Tus respuestas al test y tus propias inquietudes nos dan una visi\u00f3n muy clara de tus talentos e intereses.", "perfil": "Matias, tu perfil se destaca por una profunda curiosidad cient\u00edfica y una mente altamente anal\u00edtica. Te sientes c\u00f3modo con las Matem\u00e1ticas, la F\u00edsica y la Qu\u00edmica, y disfrutas investigando, buscando la l\u00f3gica detr\u00e1s de los fen\u00f3menos y estructurando soluciones paso a paso. Eres una persona meticulosa que valora el orden, las instrucciones claras y la revisi\u00f3n exhaustiva de la informaci\u00f3n, lo que te permite llegar al fondo de las cosas. Tu inter\u00e9s se inclina fuertemente hacia los ambientes de laboratorio, cl\u00ednicas y centros de investigaci\u00f3n, con una clara vocaci\u00f3n por el descubrimiento cient\u00edfico y, en particular, por la b\u00fasqueda de curas para enfermedades complejas. Eres h\u00e1bil explicando conceptos dif\u00edciles de ciencias, lo que demuestra tu comprensi\u00f3n y dominio en estas \u00e1reas.", "carreras_sugeridas": [{"titulo": "Medicina Humana (UNP, UDEP, UCV)", "descripcion": "Esta carrera se alinea perfectamente con tu sue\u00f1o de ''encontrar la cura para una enfermedad compleja'' y tu inter\u00e9s expl\u00edcito en Medicina. Tu perfil anal\u00edtico, tu curiosidad por los avances m\u00e9dicos y tu preferencia por los entornos de cl\u00ednica e investigaci\u00f3n te preparan muy bien para los rigores acad\u00e9micos y profesionales de esta disciplina. Las universidades de Piura ofrecen programas s\u00f3lidos en esta \u00e1rea."}, {"titulo": "Tecnolog\u00eda M\u00e9dica o Laboratorio Cl\u00ednico y Biotecnolog\u00eda (UCV, SENATI)", "descripcion": "Dado tu gusto por el laboratorio, el uso de microscopios e instrumentos de medici\u00f3n, y tu habilidad para ''analizar datos'' y ''revisar que todo tenga sentido'', una carrera enfocada en el an\u00e1lisis cl\u00ednico y la investigaci\u00f3n en laboratorio ser\u00eda una excelente opci\u00f3n. Estas profesiones son fundamentales en el proceso de descubrimiento y diagn\u00f3stico, trabajando directamente en la identificaci\u00f3n de enfermedades y el desarrollo de soluciones."}, {"titulo": "Biolog\u00eda o Ingenier\u00eda Qu\u00edmica (UNP, UDEP)", "descripcion": "Si bien tu inter\u00e9s en Medicina es claro, tu afinidad por las ''Matem\u00e1ticas, F\u00edsica o Qu\u00edmica'', los ''descubrimientos cient\u00edficos'' y los ''documentales de naturaleza'' te hacen un excelente candidato para carreras puramente cient\u00edficas. La Biolog\u00eda o la Ingenier\u00eda Qu\u00edmica te permitir\u00edan investigar a fondo, trabajar en laboratorios y contribuir al conocimiento cient\u00edfico o al desarrollo de nuevos productos y procesos, aline\u00e1ndose con tu deseo de ''investigar y encontrar verdades''."}], "conclusiones": "Matias, tienes un perfil muy definido y prometedor en el campo de las ciencias y la investigaci\u00f3n. Tu pasi\u00f3n por el descubrimiento y tu enfoque anal\u00edtico son tus mayores fortalezas. Te animo a que explores en detalle los planes de estudio de las carreras mencionadas en la Universidad Nacional de Piura (UNP), la Universidad de Piura (UDEP), la Universidad C\u00e9sar Vallejo (UCV) y SENATI. Cada una tiene sus particularidades y una de ellas, sin duda, te ofrecer\u00e1 el camino ideal para desarrollar tu talento y cumplir tus sue\u00f1os aqu\u00ed en nuestra querida Piura. \u00a1El futuro est\u00e1 lleno de posibilidades para ti!"}', '2026-06-22 12:02:35.281279', NULL);
INSERT INTO public.resultados VALUES ('fe2470a8-b66b-4bcf-86a0-6d3fb4530c5a', 'aa535c8a-5874-4052-ad12-25ae1a657d60', 1, '{"1": "Computación, Robótica o Talleres técnicos (Crear y armar cosas).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Busco una forma creativa, diferente o ''fuera de la caja'' para resolverlo.", "4": "En un estudio de diseño, teatro, o viajando constantemente.", "5": "El líder que expone, reparte los temas y organiza los tiempos.", "6": "Descubrimientos científicos, avances médicos o documentales de naturaleza.", "7": "Una cámara profesional, un lienzo o un programa de diseño gráfico.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Empezando a armarlo directamente, aprendiendo mediante la práctica y el error.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, LUIS GABRIEL! Es un gusto para m\u00ed analizar tu perfil vocacional y explorar las emocionantes posibilidades que el futuro te depara aqu\u00ed en Piura.", "perfil": "LUIS GABRIEL, tu perfil destaca por una marcada inclinaci\u00f3n hacia la tecnolog\u00eda y la innovaci\u00f3n. Muestras un gran entusiasmo por la computaci\u00f3n, la rob\u00f3tica y los talleres t\u00e9cnicos, disfrutando crear, armar y arreglar cosas, lo que sugiere una mente pr\u00e1ctica y orientada a la acci\u00f3n. Eres un solucionador de problemas creativo, buscando siempre enfoques ''fuera de la caja'' y proponiendo m\u00e9todos m\u00e1s eficientes. Tu esp\u00edritu emprendedor y tu ambici\u00f3n son evidentes, con el sue\u00f1o de fundar una startup tecnol\u00f3gica que revolucione el mercado y la aspiraci\u00f3n de liderar proyectos grandes con \u00e9xito econ\u00f3mico. Adem\u00e1s, posees habilidades de liderazgo y organizaci\u00f3n, te comunicas eficazmente y disfrutas del trabajo en equipo, mostrando empat\u00eda y una disposici\u00f3n a ayudar a los dem\u00e1s. Aprendes mejor mediante la pr\u00e1ctica y el error, lo que refuerza tu naturaleza exploradora y experimental. Tu inter\u00e9s en el dise\u00f1o gr\u00e1fico y la exploraci\u00f3n tecnol\u00f3gica complementa tu visi\u00f3n innovadora.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda Mecatr\u00f3nica (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP)", "descripcion": "Esta carrera es ideal para ti, LUIS GABRIEL, ya que combina tu inter\u00e9s en la rob\u00f3tica, la creaci\u00f3n y el armado de cosas (Preguntas 1, 2, 13). Te permitir\u00e1 aplicar tu habilidad para arreglar aparatos (P11) y tu enfoque pr\u00e1ctico para resolver problemas. Desarrollar\u00e1s sistemas automatizados, robots y maquinaria inteligente, lo cual encaja con tu deseo de explorar tecnolog\u00eda y tu mentalidad de descubrimiento cient\u00edfico (P6)."}, {"titulo": "Ingenier\u00eda de Sistemas / Ingenier\u00eda de Software (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Dada tu pasi\u00f3n por la computaci\u00f3n, la exploraci\u00f3n tecnol\u00f3gica, el desarrollo de soluciones creativas (P1, 2, 3) y tu sue\u00f1o de fundar una startup tecnol\u00f3gica (P12), estas ingenier\u00edas son perfectas. Te capacitar\u00e1n para liderar proyectos tecnol\u00f3gicos (P5, 9), dise\u00f1ar sistemas innovadores, desarrollar software y aplicaciones, y aplicar tu pensamiento eficiente (P10) para revolucionar el mercado peruano. Tus habilidades comunicativas y de trabajo en equipo (P14) ser\u00e1n cruciales para dirigir equipos y proyectos."}, {"titulo": "Dise\u00f1o Gr\u00e1fico Digital (SENATI)", "descripcion": "Aunque tu enfoque es tecnol\u00f3gico, tus respuestas tambi\u00e9n revelan una fuerte vena creativa y un inter\u00e9s en el dise\u00f1o (P3, 4, 7). Esta carrera t\u00e9cnica te permitir\u00eda canalizar tu pensamiento ''fuera de la caja'' y tu habilidad para usar programas de dise\u00f1o gr\u00e1fico (P7). Es una excelente opci\u00f3n para desarrollar tu creatividad y aplicar tus conocimientos tecnol\u00f3gicos en la creaci\u00f3n de soluciones visuales impactantes, que son esenciales para cualquier startup o proyecto innovador."}], "conclusiones": "LUIS GABRIEL, tienes un perfil sumamente prometedor, con una clara vocaci\u00f3n tecnol\u00f3gica, un esp\u00edritu innovador y un fuerte deseo de liderazgo y emprendimiento. Las instituciones educativas de Piura, como la UNP, UDEP, UCV y SENATI, ofrecen programas que se alinean perfectamente con tus intereses y habilidades. Te animo a investigar a fondo estas opciones, visitar sus campus y hablar con profesionales de estas \u00e1reas. \u00a1Tu entusiasmo por aprender de tecnolog\u00eda, combinado con tu creatividad y ambici\u00f3n, te abrir\u00e1 muchas puertas para construir un futuro exitoso y con gran impacto aqu\u00ed en nuestra querida Piura!"}', '2026-06-22 12:06:45.261018', NULL);
INSERT INTO public.resultados VALUES ('227c0061-866d-4e3d-b3cd-90c4bc76da8e', '83e31970-fb43-4b58-bc3f-02d85bbf692d', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El que investiga a fondo, recopila la información y revisa que todo tenga sentido.", "6": "Descubrimientos científicos, avances médicos o documentales de naturaleza.", "7": "Un microscopio, instrumentos de medición o software de datos.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El descubrimiento: poder investigar y encontrar verdades o curas.", "10": "Me encantan; prefiero tener instrucciones claras, orden y saber qué esperar.", "11": "Para que les explique tareas difíciles de matemáticas o ciencias.", "12": "Encontrar la cura para una enfermedad compleja.", "13": "Viendo un tutorial en video y fijándome en los detalles visuales.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, NELSON LEONEL! Es un gusto para m\u00ed analizar tus respuestas del test vocacional y ayudarte a explorar tu futuro acad\u00e9mico y profesional aqu\u00ed en nuestra querida Piura.", "perfil": "Nelson, tus respuestas revelan un perfil de estudiante con una marcada inclinaci\u00f3n hacia las **ciencias exactas** como las Matem\u00e1ticas, F\u00edsica y Qu\u00edmica, donde demuestras una gran habilidad para comprender y explicar conceptos complejos. Eres una persona con una mente profundamente **anal\u00edtica, l\u00f3gica e investigadora**, que disfruta desentra\u00f1ar problemas, buscar la verdad y estructurar soluciones paso a paso. Tu inter\u00e9s se centra claramente en el **descubrimiento cient\u00edfico**, los avances m\u00e9dicos y el trabajo en **laboratorios o centros de investigaci\u00f3n**, donde te sientes c\u00f3modo utilizando instrumentos de medici\u00f3n y analizando datos. Valoras el orden, las instrucciones claras y te describes como alguien pr\u00e1ctico, de acci\u00f3n r\u00e1pida, que busca ver **resultados f\u00edsicos y tangibles**. Tu motivaci\u00f3n principal parece ser la de **encontrar curas o soluciones a problemas complejos**, especialmente en el \u00e1mbito de la salud y la ciencia.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda Qu\u00edmica (Universidad Nacional de Piura - UNP)", "descripcion": "Esta carrera se alinea perfectamente con tu amor por la Qu\u00edmica, el c\u00e1lculo y las ciencias exactas (Pregunta 1). Te permitir\u00e1 trabajar en un laboratorio (Pregunta 4) investigando a fondo (Pregunta 5), analizando datos y estructurando soluciones (Pregunta 3) para obtener resultados f\u00edsicos y pr\u00e1cticos (Pregunta 14). Es una excelente opci\u00f3n para aplicar tu mente l\u00f3gica y tu deseo de descubrimiento."}, {"titulo": "Biolog\u00eda / Ciencias Biol\u00f3gicas (Universidad Nacional de Piura - UNP)", "descripcion": "Tu fascinaci\u00f3n por los descubrimientos cient\u00edficos, los avances m\u00e9dicos y los documentales de naturaleza (Pregunta 6), junto con tu inter\u00e9s en usar un microscopio (Pregunta 7) y tu gran anhelo de encontrar la cura para una enfermedad compleja (Pregunta 12), te llevar\u00edan directamente a este campo. Aqu\u00ed podr\u00edas satisfacer tu pasi\u00f3n por la investigaci\u00f3n y el descubrimiento de nuevas verdades o curas (Pregunta 9) en un laboratorio o centro de investigaci\u00f3n (Pregunta 4)."}, {"titulo": "Medicina Humana con enfoque en Investigaci\u00f3n (Universidad de Piura - UDEP / Universidad Nacional de Piura - UNP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Aunque Medicina es una carrera cl\u00ednica, tu deseo de ''encontrar la cura para una enfermedad compleja'' (Pregunta 12), tu inter\u00e9s en ''avances m\u00e9dicos'' (Pregunta 6) y tu preferencia por un ''laboratorio, cl\u00ednica o centro de investigaci\u00f3n'' (Pregunta 4) sugieren que podr\u00edas orientar tu trayectoria hacia la investigaci\u00f3n m\u00e9dica. Tu habilidad para las ciencias exactas (Pregunta 1), tu enfoque anal\u00edtico y l\u00f3gico (Pregunta 3), y tu deseo de investigar a fondo (Pregunta 5) ser\u00edan fundamentales en esta rama."}], "conclusiones": "Nelson, tienes un perfil muy claro y prometedor, con una gran pasi\u00f3n por la ciencia, la investigaci\u00f3n y la b\u00fasqueda de soluciones. Las instituciones educativas de Piura, como la Universidad Nacional de Piura (UNP), la Universidad de Piura (UDEP) y la Universidad C\u00e9sar Vallejo (UCV), ofrecen excelentes programas que se ajustan a tus intereses. Te animo a que investigues m\u00e1s a fondo estas opciones, visites sus campus si es posible y converses con profesionales de estas \u00e1reas. \u00a1Tu futuro en la ciencia y el descubrimiento es muy brillante aqu\u00ed en Piura!"}', '2026-06-22 12:09:06.314057', NULL);
INSERT INTO public.resultados VALUES ('6e3f9eb9-54ee-4a0e-8a49-22ff95e2cea5', 'c648dcca-2b65-47f9-a043-c5bddee367e2', 1, '{"1": "Comunicación, Arte o Historia (Lectura, expresión y sociedad).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Busco una forma creativa, diferente o ''fuera de la caja'' para resolverlo.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Hojas de cálculo (Excel), agendas de negocios y gráficos financieros.", "8": "Diseñar los afiches y las campañas de publicidad para redes sociales.", "9": "La independencia: tener libertad para expresar mis ideas sin horarios estrictos.", "10": "Me adapto fácilmente si eso ayuda a que el grupo funcione mejor.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Escribir un libro o dirigir una película que impacte a millones.", "13": "Viendo un tutorial en video y fijándome en los detalles visuales.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, LUCIANA DANELLA! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y acompa\u00f1arte en este importante momento de decisi\u00f3n. Tu entusiasmo por el dise\u00f1o gr\u00e1fico es un excelente punto de partida, y tus respuestas nos dan mucha claridad.", "perfil": "Luciana, tu perfil es el de una persona notablemente **creativa e innovadora** (Pregunta 3, 8, 12, 13), siempre buscando soluciones ''fuera de la caja'' y con una fuerte inclinaci\u00f3n hacia la expresi\u00f3n visual y art\u00edstica. Muestras un inter\u00e9s genuino en la **comunicaci\u00f3n y el impacto social** (Pregunta 1, 6, 12), deseando que tus ideas resuenen y generen un cambio. Adem\u00e1s, posees una clara **aptitud tecnol\u00f3gica y pr\u00e1ctica** (Pregunta 2, 11, 14), disfrutando de explorar la tecnolog\u00eda, arreglar cosas y ver resultados tangibles de tu trabajo. No solo eres creativa, sino que tambi\u00e9n tienes una **visi\u00f3n empresarial y organizativa** (Pregunta 4, 7), lo que sugiere que te sentir\u00edas c\u00f3moda en entornos corporativos, dirigiendo proyectos o incluso tu propia empresa, valorando la independencia para expresar tus ideas (Pregunta 9). Tu capacidad de adaptaci\u00f3n y tu rol como conciliadora (Pregunta 5, 10) demuestran habilidades interpersonales y de trabajo en equipo. En resumen, eres una persona con una mente creativa, orientada a la acci\u00f3n, con habilidades tecnol\u00f3gicas y un inter\u00e9s en el mundo empresarial y comunicativo, lo cual se alinea perfectamente con tu inter\u00e9s en el dise\u00f1o gr\u00e1fico.", "carreras_sugeridas": [{"titulo": "Dise\u00f1o Gr\u00e1fico Digital (SENATI)", "descripcion": "Esta carrera t\u00e9cnica es ideal para ti, Luciana, si buscas una formaci\u00f3n pr\u00e1ctica y orientada a la acci\u00f3n, que te permita ver resultados f\u00edsicos r\u00e1pidamente (Pregunta 14). SENATI es reconocido por su enfoque en habilidades t\u00e9cnicas y tecnol\u00f3gicas (Pregunta 2, 11), prepar\u00e1ndote directamente para el mundo laboral en \u00e1reas como el dise\u00f1o de afiches, campa\u00f1as publicitarias para redes sociales (Pregunta 8) y la creaci\u00f3n de contenido visual impactante, justo como lo deseas."}, {"titulo": "Ciencias de la Comunicaci\u00f3n con especialidad en Dise\u00f1o Gr\u00e1fico y Publicidad (Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Si tu inter\u00e9s se inclina m\u00e1s hacia una formaci\u00f3n universitaria que combine tu pasi\u00f3n por el dise\u00f1o con una base te\u00f3rica y estrat\u00e9gica m\u00e1s amplia, esta opci\u00f3n es excelente. Te permitir\u00e1 desarrollar tu lado creativo y de impacto (Pregunta 1, 3, 8, 12), mientras aprendes sobre la gesti\u00f3n de campa\u00f1as, marketing digital y la direcci\u00f3n de proyectos, lo cual conecta con tu inter\u00e9s en una oficina corporativa o dirigiendo tu propia empresa (Pregunta 4, 7). Abordar\u00e1s el dise\u00f1o desde una perspectiva integral de comunicaci\u00f3n y negocios."}, {"titulo": "Comunicaci\u00f3n con menci\u00f3n en Publicidad y Marketing o Audiovisual (Universidad de Piura - UDEP)", "descripcion": "Esta carrera en UDEP te ofrecer\u00eda una formaci\u00f3n de alto nivel que potenciar\u00eda tu creatividad (Pregunta 3, 8, 12) y tu capacidad de expresi\u00f3n (Pregunta 1). Podr\u00edas especializarte en \u00e1reas que te permitan dise\u00f1ar campa\u00f1as publicitarias estrat\u00e9gicas, crear contenido audiovisual o incluso explorar la direcci\u00f3n de proyectos que impacten a millones. Esto se alinea con tu deseo de independencia (Pregunta 9) y tu inter\u00e9s en el mundo empresarial (Pregunta 4, 7), d\u00e1ndote herramientas para liderar y generar un gran impacto visual y comunicativo."}], "conclusiones": "Luciana, tu inter\u00e9s en el dise\u00f1o gr\u00e1fico es muy claro y tus respuestas lo respaldan con creces. Ya sea que elijas una carrera t\u00e9cnica o universitaria, Piura te ofrece excelentes opciones para desarrollar tu talento. La clave est\u00e1 en definir si prefieres una ruta m\u00e1s pr\u00e1ctica y enfocada en la producci\u00f3n inmediata (como el dise\u00f1o gr\u00e1fico digital t\u00e9cnico) o una ruta m\u00e1s estrat\u00e9gica y de gesti\u00f3n que te brinde una visi\u00f3n m\u00e1s amplia de la comunicaci\u00f3n y el negocio (como las carreras universitarias en Comunicaci\u00f3n con especializaciones). Ambas te permitir\u00e1n explorar tu lado creativo, tecnol\u00f3gico y con visi\u00f3n de negocio. \u00a1Conf\u00eda en tu intuici\u00f3n y en tus habilidades, tienes un futuro brillante por delante en el campo que elijas!"}', '2026-06-22 12:11:03.667128', NULL);
INSERT INTO public.resultados VALUES ('740c2224-551a-460d-ae97-dec8093958e1', '98a6e79c-3a1e-4886-8802-79f43758a09c', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Saliendo con amigos, en actividades grupales o ayudando a otros.", "3": "Pido opiniones, converso con mi equipo y buscamos una solución juntos.", "4": "En campo, construcciones, plantas industriales o al aire libre.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Me adapto fácilmente si eso ayuda a que el grupo funcione mejor.", "11": "Para que les ayude a organizar un evento, fiesta o vender algo.", "12": "Diseñar y construir un puente o edificio moderno para tu ciudad.", "13": "Pidiéndole a alguien que ya sepa que me explique paso a paso.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, BRYANT JHAIR! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y ofrecerte algunas perspectivas para tu futuro.", "perfil": "BRYANT JHAIR, tu perfil destaca por una fascinante y potente combinaci\u00f3n de aptitudes. Por un lado, demuestras una fuerte inclinaci\u00f3n hacia las ciencias exactas, el c\u00e1lculo, la f\u00edsica y la qu\u00edmica, as\u00ed como un claro inter\u00e9s por los entornos pr\u00e1cticos como construcciones, plantas industriales y el trabajo al aire libre. Te atraen los planos arquitect\u00f3nicos, los manuales t\u00e9cnicos y las herramientas de taller, y sue\u00f1as con dise\u00f1ar y construir estructuras modernas para tu ciudad. Esto revela una mente anal\u00edtica, pr\u00e1ctica y con una clara vocaci\u00f3n por la ingenier\u00eda y el dise\u00f1o.\n\nPor otro lado, eres una persona marcadamente emp\u00e1tica, comunicativa y orientada al servicio. Disfrutas de las actividades grupales, colaboras activamente pidiendo opiniones y buscando soluciones con tu equipo, y te describes como un conciliador que ayuda a los dem\u00e1s. Tu inter\u00e9s en temas de salud mental, derechos humanos y causas sociales, junto con tu motivaci\u00f3n por sentir que tu trabajo mejora la vida de tu comunidad, subraya una profunda vocaci\u00f3n humanitaria y social. Eres adaptable, priorizas el buen funcionamiento del grupo y disfrutas ense\u00f1ando o asistiendo a otros. Esta dualidad te posiciona para carreras que combinen el rigor t\u00e9cnico con un fuerte impacto social y humano.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda Civil (Universidad Nacional de Piura, Universidad de Piura o Universidad C\u00e9sar Vallejo)", "descripcion": "Esta carrera encaja perfectamente con tu inter\u00e9s en las matem\u00e1ticas, la f\u00edsica y las ciencias exactas, as\u00ed como tu clara preferencia por el trabajo en campo, las construcciones y los planos arquitect\u00f3nicos. Tu sue\u00f1o de dise\u00f1ar y construir un puente o edificio moderno para tu ciudad se alinea directamente aqu\u00ed. Adem\u00e1s, te permitir\u00e1 cumplir con tu vocaci\u00f3n de servicio al mejorar directamente la calidad de vida de tu comunidad a trav\u00e9s de proyectos de desarrollo urbano y rural, combinando tu mente anal\u00edtica con tu deseo de impactar positivamente."}, {"titulo": "Trabajo Social (Universidad Nacional de Piura)", "descripcion": "Considerando tu gran empat\u00eda, tu deseo de ayudar a otros, tu inter\u00e9s en temas de salud mental, derechos humanos y causas sociales, y tu motivaci\u00f3n por mejorar la vida de la comunidad, Trabajo Social es una opci\u00f3n muy s\u00f3lida. Esta carrera te permitir\u00eda trabajar directamente con personas y grupos, mediando, apoyando y buscando soluciones a problemas sociales, aline\u00e1ndose con tu perfil conciliador y tu gusto por el trabajo en equipo. Esta opci\u00f3n se alinea con tu menci\u00f3n de ''carreras de letras'' al ser una ciencia social aplicada y con tu inter\u00e9s en postular a la Nacional de Piura."}, {"titulo": "Psicolog\u00eda (Universidad Nacional de Piura, Universidad de Piura o Universidad C\u00e9sar Vallejo)", "descripcion": "Tu inter\u00e9s en temas de salud mental, tu rol de conciliador y tu capacidad para comprender y ayudar a otros, hacen de la Psicolog\u00eda una excelente alternativa. Esta carrera te permitir\u00eda aplicar tu empat\u00eda y habilidades comunicativas para asistir a individuos y grupos, promoviendo el bienestar, la salud mental y la resoluci\u00f3n de conflictos, lo cual resuena con tu deseo de servicio y tu enfoque en las personas. Tambi\u00e9n se considera una carrera de ''letras'' dentro de las ciencias sociales, y tienes varias opciones en Piura para estudiarla."}], "conclusiones": "BRYANT JHAIR, tienes un perfil muy completo y valioso. La combinaci\u00f3n de tu mente anal\u00edtica y tu gran coraz\u00f3n para el servicio te abre muchas puertas. Te animo a investigar a fondo estas opciones, visitar las universidades en Piura que ofrecen estas carreras y conversar con profesionales de estas \u00e1reas. Recuerda que tu futuro es prometedor y que tu capacidad de impactar positivamente en nuestra querida regi\u00f3n Piura est\u00e1 asegurada. \u00a1Mucho \u00e9xito en tu camino vocacional!"}', '2026-06-22 12:16:30.177605', NULL);
INSERT INTO public.resultados VALUES ('2da32057-8f2f-4533-b10e-5d93c3837cf7', '4a8acfed-0e2e-425f-83fe-efafbbcb890b', 1, '{"1": "Psicología, Tutoría o Educación Física (Trabajar con personas y bienestar).", "2": "Saliendo con amigos, en actividades grupales o ayudando a otros.", "3": "Pido opiniones, converso con mi equipo y buscamos una solución juntos.", "4": "En campo, construcciones, plantas industriales o al aire libre.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Me adapto fácilmente si eso ayuda a que el grupo funcione mejor.", "11": "Para que les ayude a organizar un evento, fiesta o vender algo.", "12": "Diseñar y construir un puente o edificio moderno para tu ciudad.", "13": "Pidiéndole a alguien que ya sepa que me explique paso a paso.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, CAMILLA! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y acompa\u00f1arte en este importante momento de exploraci\u00f3n de tu futuro.", "perfil": "Camilla, tus respuestas revelan un perfil multifac\u00e9tico y muy valioso. Destaca tu fuerte vocaci\u00f3n hacia el trabajo con personas y el servicio a la comunidad. Eres una persona emp\u00e1tica, comunicativa y te desenvuelves con gran facilidad en actividades grupales, donde tu rol de conciliadora y tu capacidad para ayudar a quienes no entienden son muy apreciados. Te motiva profundamente el sentido de servicio, buscando que tu trabajo mejore la vida de tu comunidad, especialmente en temas de salud mental, derechos humanos o causas sociales. Te adaptas f\u00e1cilmente para que el grupo funcione mejor y disfrutas de la colaboraci\u00f3n para encontrar soluciones. Por otro lado, tambi\u00e9n muestras un inter\u00e9s claro y espec\u00edfico por el \u00e1mbito pr\u00e1ctico, las construcciones y el trabajo al aire libre. Te atraen los manuales de maquinaria, los planos arquitect\u00f3nicos y la idea de dise\u00f1ar y construir infraestructuras modernas para tu ciudad, lo que indica una inclinaci\u00f3n hacia la creaci\u00f3n tangible y el impacto en el entorno f\u00edsico.", "carreras_sugeridas": [{"titulo": "Trabajo Social (Universidad Nacional de Piura - UNP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera se alinea directamente con tu deseo de ayudar a otros, tu inter\u00e9s en causas sociales y tu vocaci\u00f3n de mejorar la vida de tu comunidad. Como Trabajadora Social, podr\u00edas canalizar tu empat\u00eda y habilidades comunicativas para ser una conciliadora, apoyar a grupos vulnerables, promover derechos humanos y contribuir al bienestar social, tal como lo indicaste en varias de tus respuestas. Es una profesi\u00f3n que te permitir\u00eda un impacto directo y significativo en la vida de las personas."}, {"titulo": "Psicolog\u00eda (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Tu inter\u00e9s expl\u00edcito en Psicolog\u00eda y en temas de salud mental, sumado a tu marcada inclinaci\u00f3n por trabajar con personas y promover su bienestar, hacen de esta una opci\u00f3n muy s\u00f3lida. Tu perfil emp\u00e1tico, conciliador y tu disfrute por la comunicaci\u00f3n y el trabajo en equipo ser\u00edan herramientas fundamentales para desarrollarte en este campo, ayudando a individuos y grupos a comprenderse mejor y a gestionar sus emociones y relaciones."}, {"titulo": "Ingenier\u00eda Civil (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Aunque tu vocaci\u00f3n de servicio social es muy fuerte, tus respuestas tambi\u00e9n revelan una clara atracci\u00f3n por el trabajo en campo, las construcciones, los planos arquitect\u00f3nicos y la visi\u00f3n de dise\u00f1ar y edificar infraestructuras como puentes o edificios para tu ciudad. La Ingenier\u00eda Civil te permitir\u00eda combinar tu deseo de contribuir a la comunidad con tu inter\u00e9s por lo pr\u00e1ctico y tangible, aplicando tus habilidades de trabajo en equipo y resoluci\u00f3n de problemas para crear espacios y estructuras que beneficien directamente a la sociedad piurana."}], "conclusiones": "Camilla, tu perfil es una mezcla fascinante de vocaci\u00f3n de servicio y un claro inter\u00e9s por la creaci\u00f3n y el impacto tangible en tu entorno. Si bien mencionas tu inter\u00e9s en medicina, tus respuestas del test destacan fuertemente tu deseo de trabajar directamente con las personas en roles de apoyo social o psicol\u00f3gico, y tambi\u00e9n en la creaci\u00f3n de infraestructuras que beneficien a tu comunidad. Te animo a explorar a fondo estas carreras que tan bien encajan con tu personalidad emp\u00e1tica, comunicativa y proactiva. En Piura, cuentas con excelentes instituciones como la UNP, UDEP y UCV que te ofrecen estas oportunidades. \u00a1Conf\u00eda en tus fortalezas y en tu gran potencial para generar un impacto positivo en el mundo!"}', '2026-06-22 12:18:00.868309', NULL);
INSERT INTO public.resultados VALUES ('55ac72e2-059d-4d25-8e37-093d1999037a', 'd5bf3913-a8cb-4071-b82f-06992b6a600f', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Tomo el liderazgo, organizo a los demás y tomo decisiones rápidas.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El que diseña las diapositivas, hace la carátula y le da el toque visual.", "6": "Economía, negocios, emprendimientos o política local e internacional.", "7": "Una cámara profesional, un lienzo o un programa de diseño gráfico.", "8": "Diseñar los afiches y las campañas de publicidad para redes sociales.", "9": "La independencia: tener libertad para expresar mis ideas sin horarios estrictos.", "10": "Me frustran un poco; prefiero la flexibilidad y hacer las cosas a mi modo.", "11": "Para pedirme un consejo personal o porque sé escuchar muy bien.", "12": "Escribir un libro o dirigir una película que impacte a millones.", "13": "Viendo un tutorial en video y fijándome en los detalles visuales.", "14": "Soy una persona creativa, original y muy conectada con mis emociones."}', '{"saludo": "\u00a1Hola, FABIO ADRIANO! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y acompa\u00f1arte en este emocionante camino hacia tu futuro profesional aqu\u00ed en Piura.", "perfil": "Basado en tus respuestas, Fabio, destacas por una combinaci\u00f3n muy interesante de habilidades anal\u00edticas y una marcada inclinaci\u00f3n creativa. Tienes una mente que disfruta de las matem\u00e1ticas y las ciencias exactas, lo que sugiere capacidad para el an\u00e1lisis y la resoluci\u00f3n de problemas estructurados. Al mismo tiempo, demuestras una gran pasi\u00f3n por la tecnolog\u00eda, explorando su funcionamiento y arreglando cosas, lo que indica curiosidad y habilidad pr\u00e1ctica. Eres un l\u00edder natural, proactivo, con facilidad para organizar y tomar decisiones r\u00e1pidas, y te ves dirigiendo tu propia empresa o trabajando en entornos corporativos. Tu talento visual y creativo es innegable: disfrutas dise\u00f1ando, dando un toque est\u00e9tico a los proyectos y te sientes atra\u00eddo por herramientas como c\u00e1maras, lienzos o programas de dise\u00f1o gr\u00e1fico. De hecho, tu inter\u00e9s en dise\u00f1ar afiches y campa\u00f1as para redes sociales conecta directamente con tu sue\u00f1o. Valoras la independencia y la flexibilidad, lo que te impulsa a buscar caminos donde puedas expresar tus ideas y trabajar a tu modo. Eres una persona creativa, original y emocionalmente conectada, lo que te permite generar ideas impactantes y comunicarlas visualmente.", "carreras_sugeridas": [{"titulo": "Comunicaci\u00f3n de Marketing (Universidad de Piura - UDEP)", "descripcion": "Esta carrera es ideal para ti, Fabio, porque combina tu inter\u00e9s en el mundo de los negocios y el emprendimiento con tu fuerte inclinaci\u00f3n por el dise\u00f1o y la comunicaci\u00f3n visual. Te permitir\u00e1 desarrollar estrategias de publicidad y branding, gestionar campa\u00f1as en redes sociales (tu sue\u00f1o expl\u00edcito) y entender el comportamiento del consumidor. La UDEP es reconocida por formar profesionales con visi\u00f3n estrat\u00e9gica y habilidades de liderazgo, lo que encaja perfectamente con tu perfil de toma de decisiones y organizaci\u00f3n."}, {"titulo": "Marketing y Direcci\u00f3n de Empresas (Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Aqu\u00ed podr\u00e1s potenciar tu esp\u00edritu emprendedor y tu habilidad para el liderazgo. La carrera te brindar\u00e1 herramientas para gestionar empresas, desarrollar productos y, crucialmente para ti, dise\u00f1ar e implementar estrategias de marketing digital y publicidad, incluyendo el manejo de redes sociales. Tu gusto por la econom\u00eda, los negocios y la creaci\u00f3n de campa\u00f1as de alto impacto se alinea directamente con el enfoque pr\u00e1ctico y empresarial de la UCV."}, {"titulo": "Dise\u00f1o Gr\u00e1fico Digital (SENATI)", "descripcion": "Si tu pasi\u00f3n por el dise\u00f1o visual y la creaci\u00f3n de contenido es lo que m\u00e1s te mueve, esta carrera t\u00e9cnica te dar\u00e1 las habilidades pr\u00e1cticas y directas para ello. Aprender\u00e1s a usar programas de dise\u00f1o gr\u00e1fico, crear\u00e1s afiches, logotipos, animaciones y material visual para campa\u00f1as publicitarias y, por supuesto, para redes sociales. Es una excelente opci\u00f3n para aplicar tu creatividad, tu atenci\u00f3n a los detalles visuales y tu inter\u00e9s en el dise\u00f1o de manera inmediata y efectiva en el mercado laboral de Piura."}], "conclusiones": "FABIO ADRIANO, tu perfil es el de un l\u00edder creativo y estrat\u00e9gico, con una clara visi\u00f3n hacia el impacto en el mundo digital y empresarial. Tienes la energ\u00eda y el talento para convertir tu inter\u00e9s en las redes sociales en una carrera exitosa y muy demandada. Te animo a investigar m\u00e1s a fondo estas opciones en Piura, visitar las instituciones y conversar con profesionales de estos campos. \u00a1Tu futuro est\u00e1 lleno de posibilidades y estoy seguro de que tomar\u00e1s las mejores decisiones para alcanzar tus metas!"}', '2026-06-22 12:20:54.323826', NULL);
INSERT INTO public.resultados VALUES ('24d088d3-b113-4e1b-a6a6-428ca81a57b8', '9d9e1a17-f4d2-432a-8f8d-194652cdab46', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Tomo el liderazgo, organizo a los demás y tomo decisiones rápidas.", "4": "En campo, construcciones, plantas industriales o al aire libre.", "5": "El líder que expone, reparte los temas y organiza los tiempos.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Hojas de cálculo (Excel), agendas de negocios y gráficos financieros.", "8": "Ir al campo a construir casas, limpiar playas o plantar árboles.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para que les ayude a organizar un evento, fiesta o vender algo.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Empezando a armarlo directamente, aprendiendo mediante la práctica y el error.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, jose! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y ofrecerte algunas perspectivas basadas en tus interesantes respuestas.", "perfil": "Jose, tus respuestas revelan un perfil de estudiante altamente anal\u00edtico y pr\u00e1ctico, con una marcada inclinaci\u00f3n hacia las ciencias exactas como las Matem\u00e1ticas, F\u00edsica y Qu\u00edmica. Eres un l\u00edder natural, proactivo, que disfruta organizando, tomando decisiones r\u00e1pidas y proponiendo estrategias. Te sientes c\u00f3modo trabajando en entornos din\u00e1micos, ya sea en campo, construcciones o plantas industriales, buscando siempre resultados tangibles y f\u00edsicos. Tu esp\u00edritu innovador te impulsa a investigar, buscar la eficiencia y proponer mejoras, incluso desafiando las normas si encuentras una forma m\u00e1s l\u00f3gica o productiva. Adem\u00e1s, demuestras un fuerte sentido emprendedor, con inter\u00e9s en el \u00e1mbito de los negocios, las finanzas y la posibilidad de crear proyectos que generen un impacto positivo. Tu deseo de que tu trabajo mejore la vida de tu comunidad es una motivaci\u00f3n clave, y tu estilo de aprendizaje es claramente pr\u00e1ctico, basado en la acci\u00f3n y la experimentaci\u00f3n.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda Civil (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera se alinea perfectamente con tu inter\u00e9s en las construcciones, el trabajo en campo y la obtenci\u00f3n de resultados f\u00edsicos. Tu liderazgo, capacidad de organizaci\u00f3n y deseo de mejorar la vida de la comunidad a trav\u00e9s de la infraestructura encontrar\u00e1n un gran campo de acci\u00f3n aqu\u00ed, permiti\u00e9ndote ver el impacto directo de tu trabajo."}, {"titulo": "Ingenier\u00eda Industrial (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Tu habilidad para armar estrategias, buscar la eficiencia, organizar a los dem\u00e1s y tu inter\u00e9s en plantas industriales, agendas de negocios y gr\u00e1ficos financieros te har\u00edan destacar en esta profesi\u00f3n. Es ideal para tu esp\u00edritu emprendedor y tu deseo de fundar una startup que revolucione el mercado, enfoc\u00e1ndote en la optimizaci\u00f3n de procesos, la gesti\u00f3n y la innovaci\u00f3n de productos o servicios."}, {"titulo": "Ingenier\u00eda Mec\u00e1nica (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP)", "descripcion": "Considerando tu inter\u00e9s en ''motores'', el trabajo en plantas industriales y tu enfoque pr\u00e1ctico de ver resultados f\u00edsicos, esta carrera es una excelente opci\u00f3n. Te permitir\u00eda aplicar tus conocimientos en ciencias exactas para dise\u00f1ar, mantener y optimizar sistemas mec\u00e1nicos, lo cual se relaciona con la innovaci\u00f3n y el desarrollo de productos tangibles en diversos sectores."}], "conclusiones": "Jose, tienes un perfil muy completo y prometedor, con una clara orientaci\u00f3n hacia la ingenier\u00eda, la gesti\u00f3n y el emprendimiento. Piura cuenta con excelentes opciones en la Universidad Nacional de Piura (UNP), Universidad de Piura (UDEP) y Universidad C\u00e9sar Vallejo (UCV) que te permitir\u00e1n desarrollar todo tu potencial. Te animo a investigar a fondo estas carreras, visitar las instituciones y hablar con profesionales para tomar la mejor decisi\u00f3n. \u00a1Tu futuro est\u00e1 lleno de oportunidades para construir y liderar en nuestra regi\u00f3n!"}', '2026-06-22 12:27:07.096117', NULL);
INSERT INTO public.resultados VALUES ('25364d5a-7732-4918-b022-f4b30e00f989', '09c827b7-7e9f-4059-96a5-1f8af6e25583', 1, '{"1": "Comunicación, Arte o Historia (Lectura, expresión y sociedad).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Pido opiniones, converso con mi equipo y buscamos una solución juntos.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Hojas de cálculo (Excel), agendas de negocios y gráficos financieros.", "8": "Ir al campo a construir casas, limpiar playas o plantar árboles.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Empezando a armarlo directamente, aprendiendo mediante la práctica y el error.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, YETZAEL ALEXANDER! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tus respuestas y acompa\u00f1arte en este importante momento. Tu entusiasmo y visi\u00f3n ya son un gran punto de partida.", "perfil": "YETZAEL, tu perfil es el de una persona con una mente muy activa y orientada a la acci\u00f3n. Demuestras una clara inclinaci\u00f3n hacia la tecnolog\u00eda, la innovaci\u00f3n y el emprendimiento, como lo evidencian tus intereses en explorar nuevas tecnolog\u00edas, arreglar aparatos y tu sue\u00f1o de fundar una startup tecnol\u00f3gica. Eres un l\u00edder innato, con ambici\u00f3n de dirigir proyectos grandes, buscar el \u00e9xito econ\u00f3mico y proponer soluciones m\u00e1s eficientes. Tu enfoque pr\u00e1ctico, tu preferencia por aprender haciendo y tu deseo de ver resultados tangibles te definen como alguien que no teme ensuciarse las manos. Adem\u00e1s, valoras el trabajo en equipo, la colaboraci\u00f3n y tienes una habilidad natural para conciliar y ayudar a los dem\u00e1s, lo que te convierte en un excelente comunicador y gestor de personas. La combinaci\u00f3n de tu visi\u00f3n empresarial y tu aptitud t\u00e9cnica es una fortaleza muy valiosa.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda de Sistemas o Ingenier\u00eda Industrial (Universidad Nacional de Piura, Universidad de Piura, Universidad C\u00e9sar Vallejo)", "descripcion": "Esta opci\u00f3n se alinea perfectamente con tu inter\u00e9s en la tecnolog\u00eda (celulares, IA, arreglar computadoras), tu esp\u00edritu emprendedor y tu deseo de dirigir proyectos. Te brindar\u00eda las herramientas para dise\u00f1ar, desarrollar y gestionar sistemas tecnol\u00f3gicos, optimizar procesos y liderar equipos, lo cual es fundamental para fundar y hacer crecer una startup tecnol\u00f3gica, tal como lo sue\u00f1as. La Ingenier\u00eda Industrial, por su parte, te dar\u00eda una base s\u00f3lida en gesti\u00f3n de operaciones y eficiencia, clave para cualquier empresa."}, {"titulo": "Administraci\u00f3n de Empresas (Universidad de Piura, Universidad Nacional de Piura, Universidad C\u00e9sar Vallejo) o Administraci\u00f3n Industrial (SENATI)", "descripcion": "Tu aspiraci\u00f3n de dirigir tu propia empresa, trabajar en un banco o una oficina corporativa, y tu habilidad con hojas de c\u00e1lculo y gr\u00e1ficos financieros, indican un fuerte perfil de gesti\u00f3n y negocios. Esta carrera te proporcionar\u00eda los conocimientos para planificar, organizar, dirigir y controlar los recursos de una organizaci\u00f3n, incluyendo el desarrollo de estrategias de negocio. Es una base excelente si tu objetivo es el liderazgo y el \u00e9xito econ\u00f3mico, y te permitir\u00eda gestionar eficazmente tu futura startup."}, {"titulo": "Mecatr\u00f3nica Industrial (SENATI) o Ingenier\u00eda Mecatr\u00f3nica / Mec\u00e1nico-El\u00e9ctrica (Universidad Nacional de Piura, Universidad de Piura)", "descripcion": "Tu inclinaci\u00f3n a ''arreglar cosas'', tu inter\u00e9s en los ''motores'' y tu forma de aprender ''arm\u00e1ndolo directamente'' se\u00f1alan una aptitud y gusto por la ingenier\u00eda pr\u00e1ctica. Estas carreras combinan mec\u00e1nica, electr\u00f3nica, inform\u00e1tica y control, permiti\u00e9ndote dise\u00f1ar, construir y mantener sistemas automatizados. Es una v\u00eda excelente para tu perfil pr\u00e1ctico y de acci\u00f3n r\u00e1pida, y te abrir\u00eda puertas para la innovaci\u00f3n en productos y soluciones f\u00edsicas, que podr\u00edan ser la base de futuros emprendimientos tecnol\u00f3gicos."}], "conclusiones": "YETZAEL, tienes un gran potencial para convertir tus sue\u00f1os en realidad aqu\u00ed mismo en Piura. Tu combinaci\u00f3n de visi\u00f3n tecnol\u00f3gica, liderazgo y enfoque pr\u00e1ctico te prepara para ser un agente de cambio y un emprendedor exitoso. Te animo a explorar a fondo estas opciones, visitar las instituciones y conversar con profesionales de estos campos. Recuerda que el camino del conocimiento es una aventura fascinante y estoy seguro de que con tu determinaci\u00f3n, lograr\u00e1s todo lo que te propongas. \u00a1El futuro es tuyo para construirlo!"}', '2026-06-22 14:20:04.44628', NULL);
INSERT INTO public.resultados VALUES ('9c0dd175-444b-478c-a329-132d53678d04', 'c771a05f-3298-4fa9-ba87-246bb19b2d77', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El que investiga a fondo, recopila la información y revisa que todo tenga sentido.", "6": "Descubrimientos científicos, avances médicos o documentales de naturaleza.", "7": "Un microscopio, instrumentos de medición o software de datos.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El descubrimiento: poder investigar y encontrar verdades o curas.", "10": "Me encantan; prefiero tener instrucciones claras, orden y saber qué esperar.", "11": "Para que les explique tareas difíciles de matemáticas o ciencias.", "12": "Escribir un libro o dirigir una película que impacte a millones.", "13": "Viendo un tutorial en video y fijándome en los detalles visuales.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, ADRIAN MARTIN! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y acompa\u00f1arte en este importante camino hacia tu futuro.", "perfil": "Bas\u00e1ndonos estrictamente en tus respuestas, ADRIAN, destacas como una persona con una marcada inclinaci\u00f3n hacia las **ciencias exactas** (Matem\u00e1ticas, F\u00edsica y Qu\u00edmica), la **investigaci\u00f3n profunda** y el **an\u00e1lisis l\u00f3gico**. Disfrutas investigando temas nuevos, armando estrategias y buscando la l\u00f3gica detr\u00e1s de los datos para estructurar soluciones paso a paso. Te sientes c\u00f3modo en **laboratorios, cl\u00ednicas o centros de investigaci\u00f3n**, donde puedes recopilar informaci\u00f3n, revisar que todo tenga sentido y trabajar con instrumentos de medici\u00f3n o software de datos. Tu motivaci\u00f3n principal es el **descubrimiento**, la b\u00fasqueda de verdades o curas, lo que demuestra una gran curiosidad intelectual y un deseo de contribuir. Adem\u00e1s, valoras las **instrucciones claras y el orden**, lo que indica una preferencia por ambientes estructurados. Complementas este perfil con habilidades de **comunicaci\u00f3n, empat\u00eda** y disfrute del **trabajo en equipo**, siendo capaz de explicar conceptos complejos a otros. Eres meticuloso y observador, prestando atenci\u00f3n a los detalles visuales.", "carreras_sugeridas": [{"titulo": "Medicina Humana (Universidad Nacional de Piura - UNP, Universidad de Piura - UDEP, Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera se alinea perfectamente con tu inter\u00e9s en los ''avances m\u00e9dicos'' y el ''descubrimiento'' de ''curas'' (Preguntas 6 y 9). Tu preferencia por trabajar en ''cl\u00ednicas o centros de investigaci\u00f3n'' (Pregunta 4), tu habilidad para el ''an\u00e1lisis de datos'' y la b\u00fasqueda de l\u00f3gica (Pregunta 3), junto con tu ''empat\u00eda, comunicaci\u00f3n'' y disfrute del ''trabajo en equipo'' (Pregunta 14), son fundamentales en el \u00e1mbito de la salud y la investigaci\u00f3n m\u00e9dica. Requiere una s\u00f3lida base en ''ciencias exactas'' como Matem\u00e1ticas, F\u00edsica y Qu\u00edmica (Pregunta 1)."}, {"titulo": "Ingenier\u00eda Industrial (Universidad Nacional de Piura - UNP, Universidad de Piura - UDEP, Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Tu habilidad para ''analizar datos, buscar la l\u00f3gica y estructurar una soluci\u00f3n paso a paso'' (Pregunta 3), as\u00ed como tu gusto por ''armar estrategias'' (Pregunta 2) y tu preferencia por ''instrucciones claras y orden'' (Pregunta 10), son pilares de esta ingenier\u00eda. Se enfoca en la optimizaci\u00f3n de procesos y la eficiencia, utilizando ''software de datos'' e ''instrumentos de medici\u00f3n'' (Pregunta 7) para la toma de decisiones. Tu capacidad para ''ayudar en la log\u00edstica, administrando las donaciones y el presupuesto'' (Pregunta 8) y tu inter\u00e9s en ''investigar a fondo'' (Pregunta 5) encajan con el rol de mejora continua y gesti\u00f3n estrat\u00e9gica."}, {"titulo": "Ingenier\u00eda Qu\u00edmica o Ingenier\u00eda Agroindustrial (Universidad Nacional de Piura - UNP)", "descripcion": "Estas ingenier\u00edas son una excelente opci\u00f3n dada tu fuerte inclinaci\u00f3n por la ''Qu\u00edmica y F\u00edsica'' (Pregunta 1), tu preferencia por el ''laboratorio o centro de investigaci\u00f3n'' (Pregunta 4) y tu inter\u00e9s en los ''descubrimientos cient\u00edficos'' (Preguntas 6 y 9). Implican ''investigar temas nuevos'' (Pregunta 2), ''analizar datos'' (Pregunta 3) y trabajar con ''instrumentos de medici\u00f3n'' (Pregunta 7). La Ingenier\u00eda Qu\u00edmica se centra en la transformaci\u00f3n de materias primas, mientras que la Agroindustrial aplica principios cient\u00edficos a la producci\u00f3n y procesamiento de alimentos, ambos campos donde tu meticulosidad y tu b\u00fasqueda de la l\u00f3gica son muy valoradas."}], "conclusiones": "ADRIAN, tu perfil es el de un pensador anal\u00edtico, curioso e investigador, con un gran potencial para contribuir en campos que requieren rigor cient\u00edfico y una mente estructurada. Las opciones educativas en Piura, como las que ofrecen la UNP, UDEP y UCV, te brindan excelentes caminos para desarrollar tus talentos. Te animo a seguir investigando estas carreras, conversando con profesionales y visitando las universidades para conocer m\u00e1s a fondo lo que cada una ofrece. \u00a1Conf\u00edo en que tomar\u00e1s una decisi\u00f3n informada y exitosa para tu futuro!"}', '2026-06-22 14:22:48.525715', NULL);
INSERT INTO public.resultados VALUES ('83b14674-ea0a-47e3-9f82-e8b17ccc5e48', '91b32701-e0fe-4ac7-896d-72c9283e0ce0', 1, '{"1": "Comunicación, Arte o Historia (Lectura, expresión y sociedad).", "2": "Dibujando, tocando un instrumento, escribiendo o creando contenido.", "3": "Tomo el liderazgo, organizo a los demás y tomo decisiones rápidas.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El líder que expone, reparte los temas y organiza los tiempos.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Ir al campo a construir casas, limpiar playas o plantar árboles.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Me frustran un poco; prefiero la flexibilidad y hacer las cosas a mi modo.", "11": "Para que les explique tareas difíciles de matemáticas o ciencias.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Pidiéndole a alguien que ya sepa que me explique paso a paso.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, ALDAIR ANGHELO PERCY!", "perfil": "Hubo un error al procesar tu an\u00e1lisis con la IA: 503 UNAVAILABLE. {''error'': {''code'': 503, ''message'': ''This model is currently experiencing high demand. Spikes in demand are usually temporary. Please try again later.'', ''status'': ''UNAVAILABLE''}}", "carreras_sugeridas": [], "conclusiones": "Por favor, intenta realizar el test m\u00e1s tarde."}', '2026-06-22 14:26:29.380113', NULL);
INSERT INTO public.resultados VALUES ('03e5e7de-c3c7-4652-a1cf-f9d61ba1d60e', '91b32701-e0fe-4ac7-896d-72c9283e0ce0', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El líder que expone, reparte los temas y organiza los tiempos.", "6": "Descubrimientos científicos, avances médicos o documentales de naturaleza.", "7": "Hojas de cálculo (Excel), agendas de negocios y gráficos financieros.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "La independencia: tener libertad para expresar mis ideas sin horarios estrictos.", "10": "Me frustran un poco; prefiero la flexibilidad y hacer las cosas a mi modo.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Diseñar y construir un puente o edificio moderno para tu ciudad.", "13": "Empezando a armarlo directamente, aprendiendo mediante la práctica y el error.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, ALDAIR ANGHELO PERCY!", "perfil": "Hubo un error al procesar tu an\u00e1lisis con la IA: 503 UNAVAILABLE. {''error'': {''code'': 503, ''message'': ''This model is currently experiencing high demand. Spikes in demand are usually temporary. Please try again later.'', ''status'': ''UNAVAILABLE''}}", "carreras_sugeridas": [], "conclusiones": "Por favor, intenta realizar el test m\u00e1s tarde."}', '2026-06-22 14:30:33.567162', NULL);
INSERT INTO public.resultados VALUES ('2bc00e91-18a7-4b92-bb1f-52d1c27a6ecb', '91b32701-e0fe-4ac7-896d-72c9283e0ce0', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Pido opiniones, converso con mi equipo y buscamos una solución juntos.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Hojas de cálculo (Excel), agendas de negocios y gráficos financieros.", "8": "Ir al campo a construir casas, limpiar playas o plantar árboles.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Me adapto fácilmente si eso ayuda a que el grupo funcione mejor.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Empezando a armarlo directamente, aprendiendo mediante la práctica y el error.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, ALDAIR ANGHELO PERCY! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tus respuestas y acompa\u00f1arte en este importante camino hacia tu futuro profesional. Tu test ha revelado un perfil muy interesante y prometedor.", "perfil": "Aldair, tus respuestas reflejan una mente muy anal\u00edtica, con una fuerte inclinaci\u00f3n hacia las ciencias exactas como las Matem\u00e1ticas, F\u00edsica y Qu\u00edmica. Demuestras una curiosidad innata por la tecnolog\u00eda, disfrutas explorando, arreglando aparatos y manteni\u00e9ndote al tanto de las innovaciones en \u00e1reas como la inteligencia artificial y los motores. Eres una persona pr\u00e1ctica, orientada a la acci\u00f3n y a la obtenci\u00f3n de resultados tangibles y f\u00edsicos. Adem\u00e1s, posees un marcado esp\u00edritu emprendedor, visualiz\u00e1ndote en roles de liderazgo, ya sea en el \u00e1mbito corporativo, financiero o dirigiendo tu propia empresa tecnol\u00f3gica. Valoras el trabajo en equipo, la colaboraci\u00f3n y tienes una habilidad natural para conciliar y facilitar el entendimiento entre tus compa\u00f1eros, lo que te convierte en un l\u00edder nato con excelentes habilidades blandas para la gesti\u00f3n de proyectos y equipos.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda de Sistemas o Ingenier\u00eda Inform\u00e1tica (UNP / UDEP / UCV)", "descripcion": "Esta carrera encaja perfectamente con tu inter\u00e9s en las ciencias exactas, tu curiosidad por la tecnolog\u00eda, los videojuegos, la inteligencia artificial y tu deseo de ''arreglar la computadora o el internet''. Te permitir\u00e1 desarrollar soluciones innovadoras, gestionar proyectos tecnol\u00f3gicos y, muy importante, te brindar\u00e1 las herramientas para cumplir tu sue\u00f1o de ''fundar una startup tecnol\u00f3gica que revolucione el mercado peruano''."}, {"titulo": "Ingenier\u00eda Electr\u00f3nica o Ingenier\u00eda Mecatr\u00f3nica (UNP / UDEP / SENATI)", "descripcion": "Considerando tu gusto por ''arreglar cosas en casa'', tu inter\u00e9s en ''motores'' y tu naturaleza ''pr\u00e1ctica, de acci\u00f3n r\u00e1pida'' que busca ''resultados f\u00edsicos'', estas ingenier\u00edas son ideales. Te enfocar\u00e1s en el dise\u00f1o, desarrollo y mantenimiento de sistemas electr\u00f3nicos y automatizados, desde dispositivos hasta maquinaria industrial. SENATI ofrece excelentes opciones t\u00e9cnicas en este campo que te permitir\u00e1n aplicar tus conocimientos de forma muy pr\u00e1ctica."}, {"titulo": "Ingenier\u00eda Industrial o Administraci\u00f3n de Empresas (UNP / UDEP / UCV / SENATI - Administraci\u00f3n Industrial)", "descripcion": "Tu visi\u00f3n de trabajar en una ''oficina corporativa, banco o dirigiendo tu propia empresa'', junto con tu manejo de ''hojas de c\u00e1lculo, agendas de negocios y gr\u00e1ficos financieros'', y tu capacidad para liderar equipos y buscar soluciones colaborativas, te hacen un excelente candidato para estas carreras. La Ingenier\u00eda Industrial te dar\u00eda una base s\u00f3lida para optimizar procesos y la Administraci\u00f3n te preparar\u00eda para la gesti\u00f3n y direcci\u00f3n de negocios, incluyendo tu futura startup tecnol\u00f3gica. SENATI tambi\u00e9n ofrece la carrera t\u00e9cnica de Administraci\u00f3n Industrial, que te da una base s\u00f3lida y pr\u00e1ctica."}], "conclusiones": "Aldair, tienes un perfil muy completo y vers\u00e1til, con una combinaci\u00f3n poderosa de habilidades anal\u00edticas, t\u00e9cnicas y de liderazgo. Recuerda que el camino que elijas te permitir\u00e1 aplicar tus talentos y contribuir al desarrollo de nuestra regi\u00f3n Piura. Te animo a investigar m\u00e1s a fondo estas opciones, visitar las instituciones y conversar con profesionales de cada campo. \u00a1Estoy seguro de que tu determinaci\u00f3n y pasi\u00f3n te llevar\u00e1n a construir un futuro exitoso y lleno de innovaci\u00f3n!"}', '2026-06-22 14:31:30.140565', NULL);
INSERT INTO public.resultados VALUES ('3c78f4d0-6fb8-4ec6-9c9c-46a79973a74d', '90e76e1f-6e9d-4910-99c8-280b9e52a3b8', 1, '{"1": "Computación, Robótica o Talleres técnicos (Crear y armar cosas).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El que investiga a fondo, recopila la información y revisa que todo tenga sentido.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Un microscopio, instrumentos de medición o software de datos.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Leyendo el manual completo antes de tocar cualquier pieza.", "14": "Soy una persona curiosa, analítica y me gusta llegar al fondo de las cosas."}', '{"saludo": "\u00a1Hola, JULIO DIEGO DE JOS\u00c9! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y ofrecerte algunas ideas para tu futuro acad\u00e9mico y profesional aqu\u00ed en Piura.", "perfil": "Julio, tus respuestas nos muestran un perfil marcadamente anal\u00edtico, l\u00f3gico y orientado a la resoluci\u00f3n de problemas. Te destacas por tu curiosidad innata, tu deseo de investigar a fondo y tu habilidad para buscar la l\u00f3gica y estructurar soluciones paso a paso. Muestras un gran inter\u00e9s por la computaci\u00f3n, la rob\u00f3tica, la tecnolog\u00eda y los talleres t\u00e9cnicos, disfrutando de crear, armar y arreglar cosas, as\u00ed como de explorar nuevas tecnolog\u00edas y sus lanzamientos. Tu mente est\u00e1 programada para el pensamiento eficiente, proponiendo mejoras cuando encuentras formas m\u00e1s l\u00f3gicas de hacer las cosas. Adem\u00e1s, se percibe un esp\u00edritu innovador y emprendedor, con la visi\u00f3n de liderar proyectos grandes y, quiz\u00e1s, fundar una startup tecnol\u00f3gica. Te sientes c\u00f3modo en entornos como laboratorios o centros de investigaci\u00f3n, utilizando instrumentos de medici\u00f3n o software de datos, lo que refuerza tu inclinaci\u00f3n hacia \u00e1reas t\u00e9cnicas y de investigaci\u00f3n.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda de Sistemas (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera se alinea perfectamente con tu inter\u00e9s en la computaci\u00f3n, la tecnolog\u00eda, el an\u00e1lisis de datos y la resoluci\u00f3n l\u00f3gica de problemas. Tu deseo de fundar una startup tecnol\u00f3gica y tu habilidad para estructurar soluciones se potenciar\u00edan en esta \u00e1rea, que te preparar\u00eda para dise\u00f1ar, desarrollar y gestionar sistemas inform\u00e1ticos y tecnol\u00f3gicos."}, {"titulo": "Ingenier\u00eda Mecatr\u00f3nica o Electr\u00f3nica (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / SENATI)", "descripcion": "Dada tu inclinaci\u00f3n por la rob\u00f3tica, los talleres t\u00e9cnicos (crear y armar), el arreglo de aparatos y tu inter\u00e9s en motores, estas ingenier\u00edas son una excelente opci\u00f3n. Podr\u00edas desarrollar sistemas automatizados, robots o dispositivos electr\u00f3nicos, combinando tus habilidades anal\u00edticas con tu gusto por lo pr\u00e1ctico y la investigaci\u00f3n en laboratorio. SENATI ofrece excelentes opciones t\u00e9cnicas en estas \u00e1reas."}, {"titulo": "Tecnolog\u00edas de la Informaci\u00f3n con especializaci\u00f3n en Desarrollo de Software o Redes (SENATI)", "descripcion": "Si buscas una formaci\u00f3n m\u00e1s t\u00e9cnica y pr\u00e1ctica en un menor tiempo, SENATI ofrece carreras que encajan con tu perfil. Aqu\u00ed podr\u00edas enfocarte en el desarrollo de software, la gesti\u00f3n de redes o el mantenimiento de equipos, lo cual se relaciona directamente con tu disfrute por arreglar computadoras, explorar tecnolog\u00eda y tu inter\u00e9s en software de datos. Es una v\u00eda directa para aplicar tus habilidades en el mundo tecnol\u00f3gico."}], "conclusiones": "Julio, tu camino en el mundo de la ingenier\u00eda y la tecnolog\u00eda luce prometedor y muy claro. Tienes un perfil s\u00f3lido para estas \u00e1reas, y tu sue\u00f1o de estudiar Ingenier\u00eda de Sistemas est\u00e1 muy bien fundamentado en tus intereses y habilidades. En Piura, cuentas con excelentes opciones como la Universidad Nacional de Piura (UNP), la Universidad de Piura (UDEP), la Universidad C\u00e9sar Vallejo (UCV) y SENATI, que pueden ayudarte a desarrollar todo tu potencial. Te animo a investigar m\u00e1s a fondo estas instituciones y sus planes de estudio. \u00a1Tu futuro est\u00e1 lleno de posibilidades y estoy seguro de que lograr\u00e1s tus metas!"}', '2026-06-22 14:33:21.249447', NULL);
INSERT INTO public.resultados VALUES ('95adfd08-667f-4070-bdec-f76bc1a10853', '6152f234-3bff-433c-adf8-7f6fbca64efd', 1, '{"1": "Psicología, Tutoría o Educación Física (Trabajar con personas y bienestar).", "2": "Saliendo con amigos, en actividades grupales o ayudando a otros.", "3": "Tomo el liderazgo, organizo a los demás y tomo decisiones rápidas.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El líder que expone, reparte los temas y organiza los tiempos.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Hojas de cálculo (Excel), agendas de negocios y gráficos financieros.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Me adapto fácilmente si eso ayuda a que el grupo funcione mejor.", "11": "Para que les ayude a organizar un evento, fiesta o vender algo.", "12": "Escribir un libro o dirigir una película que impacte a millones.", "13": "Pidiéndole a alguien que ya sepa que me explique paso a paso.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, JUNIOR JEFFERSON! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tus respuestas y sue\u00f1os para tu futuro.", "perfil": "JUNIOR, tus respuestas reflejan un perfil sumamente interesante y con un fuerte sentido de vocaci\u00f3n de servicio. Destacas por tu marcada empat\u00eda y habilidades comunicativas, disfrutando plenamente del trabajo en equipo y las actividades grupales. Tienes una clara inclinaci\u00f3n a trabajar con personas, buscando su bienestar y abordando temas importantes como la salud mental, los derechos humanos y las causas sociales, lo que demuestra tu deseo de mejorar la vida de tu comunidad. Adem\u00e1s de tu lado altruista, posees un s\u00f3lido esp\u00edritu de liderazgo y organizaci\u00f3n; te gusta tomar la iniciativa, organizar a los dem\u00e1s, tomar decisiones r\u00e1pidas y coordinar eventos. Muestras inter\u00e9s en entornos profesionales como oficinas corporativas o dirigiendo tu propia empresa, y te sientes c\u00f3modo manejando herramientas administrativas como hojas de c\u00e1lculo y agendas de negocios. Esta combinaci\u00f3n de un coraz\u00f3n social y una mente organizadora te posiciona para roles donde puedas liderar y gestionar proyectos con impacto humano.", "carreras_sugeridas": [{"titulo": "Psicolog\u00eda (Universidad Nacional de Piura - UNP, Universidad de Piura - UDEP, Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera se alinea perfectamente con tu deseo expl\u00edcito de estudiar Psicolog\u00eda y con tu fuerte inter\u00e9s en el bienestar de las personas, la salud mental y las causas sociales (Preguntas 1, 6, 9). Tu empat\u00eda, comunicaci\u00f3n y gusto por ayudar a otros (Preguntas 2, 8, 14) son cualidades esenciales. Tus habilidades de liderazgo y organizaci\u00f3n (Preguntas 3, 5, 11) ser\u00edan muy valiosas para gestionar proyectos sociales, liderar equipos o incluso dirigir tu propia consulta o instituci\u00f3n."}, {"titulo": "Administraci\u00f3n de Empresas o Gesti\u00f3n (Universidad Nacional de Piura - UNP, Universidad de Piura - UDEP, Universidad C\u00e9sar Vallejo - UCV, SENATI)", "descripcion": "Aunque tu inclinaci\u00f3n principal es social, tus respuestas tambi\u00e9n revelan una fuerte aptitud e inter\u00e9s por la organizaci\u00f3n, el liderazgo y la gesti\u00f3n (Preguntas 3, 4, 5, 7, 11). Te ves trabajando en una oficina corporativa, un banco o dirigiendo tu propia empresa, y manejando herramientas como hojas de c\u00e1lculo y gr\u00e1ficos financieros. Una carrera en Administraci\u00f3n te permitir\u00eda combinar tu deseo de impactar (Pregunta 9) con tus habilidades para organizar, liderar y tomar decisiones, aplic\u00e1ndolas en la gesti\u00f3n de organizaciones con fines sociales, ONGs, proyectos comunitarios o incluso en departamentos de recursos humanos donde tu empat\u00eda ser\u00eda un gran activo. SENATI ofrece excelentes carreras t\u00e9cnicas en administraci\u00f3n que te dar\u00edan una base s\u00f3lida."}, {"titulo": "Educaci\u00f3n (especialidad en Psicopedagog\u00eda o Gesti\u00f3n Educativa) (Universidad Nacional de Piura - UNP, Universidad de Piura - UDEP, Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Tu inter\u00e9s en la tutor\u00eda, dar clases de refuerzo a ni\u00f1os y asistir a adultos mayores (Pregunta 8), sumado a tu liderazgo natural y deseo de trabajar con personas (Preguntas 1, 3, 5, 14), hace de la Educaci\u00f3n una opci\u00f3n muy viable. Una especialidad en Psicopedagog\u00eda te permitir\u00eda aplicar tus conocimientos de psicolog\u00eda en el \u00e1mbito educativo, ayudando a estudiantes y docentes. Si te inclinas m\u00e1s por la gesti\u00f3n, podr\u00edas aspirar a roles de coordinaci\u00f3n o direcci\u00f3n educativa, donde tus habilidades organizativas y de liderazgo ser\u00edan fundamentales para mejorar el sistema educativo y la vida de la comunidad escolar."}], "conclusiones": "JUNIOR, tienes un perfil con una combinaci\u00f3n poderosa de habilidades sociales, liderazgo y capacidad organizativa. Es maravilloso que ya tengas un inter\u00e9s claro en Psicolog\u00eda, y como ves, tus respuestas lo confirman plenamente. Pero tambi\u00e9n te invito a explorar c\u00f3mo tus otras fortalezas pueden potenciar tu impacto en cualquier campo que elijas, incluso en roles de gesti\u00f3n o educaci\u00f3n. En Piura, cuentas con excelentes opciones como la UNP, UDEP, UCV y SENATI, que te brindar\u00e1n las herramientas necesarias para desarrollar tu potencial y hacer realidad tu sue\u00f1o de mejorar la vida de las personas. \u00a1Conf\u00eda en tus capacidades y sigue adelante con esa energ\u00eda y deseo de servir!"}', '2026-06-22 14:34:52.607497', NULL);
INSERT INTO public.resultados VALUES ('7e8d5864-e6b1-4caf-b924-91f6789471c3', '2ca0c299-f23b-4c78-8528-db9c99dbc80a', 1, '{"1": "Psicología, Tutoría o Educación Física (Trabajar con personas y bienestar).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Busco una forma creativa, diferente o ''fuera de la caja'' para resolverlo.", "4": "En un estudio de diseño, teatro, o viajando constantemente.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Hojas de cálculo (Excel), agendas de negocios y gráficos financieros.", "8": "Diseñar los afiches y las campañas de publicidad para redes sociales.", "9": "La independencia: tener libertad para expresar mis ideas sin horarios estrictos.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para pedirme un consejo personal o porque sé escuchar muy bien.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Pidiéndole a alguien que ya sepa que me explique paso a paso.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, MATIAS DANIEL! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y ofrecerte algunas ideas para tu futuro.", "perfil": "Matias, tu perfil revela una combinaci\u00f3n fascinante de creatividad, pragmatismo y un esp\u00edritu innovador. Muestras una clara inclinaci\u00f3n hacia el trabajo con personas, destacando tu rol como conciliador y tu capacidad de escucha, lo que sugiere empat\u00eda y habilidades interpersonales s\u00f3lidas (Pregunta 1, 5 y 11). Tu pensamiento es \"fuera de la caja\", buscando soluciones creativas y eficientes (Pregunta 3 y 10). Tienes un fuerte inter\u00e9s en el dise\u00f1o, la comunicaci\u00f3n visual y la publicidad (Pregunta 4 y 8), as\u00ed como en la tecnolog\u00eda y la innovaci\u00f3n (Pregunta 2, 6 y 12), con una visi\u00f3n emprendedora para crear impacto. Valoras la independencia y la libertad para expresar tus ideas (Pregunta 9). Eres una persona pr\u00e1ctica, orientada a la acci\u00f3n y a obtener resultados tangibles (Pregunta 14), y te sientes c\u00f3modo con herramientas de gesti\u00f3n y an\u00e1lisis (Pregunta 7). Tu preferencia por aprender paso a paso (Pregunta 13) indica una metodolog\u00eda de aprendizaje estructurada.", "carreras_sugeridas": [{"titulo": "Arquitectura (Universidad Nacional de Piura, Universidad de Piura, Universidad C\u00e9sar Vallejo)", "descripcion": "Esta carrera se alinea directamente con tu sue\u00f1o de ''Dise\u00f1o de Interiores'', ya que la arquitectura abarca la creaci\u00f3n de espacios y ambientes. Te permitir\u00e1 fusionar tu creatividad (P3, P4, P8) con tu deseo de ver resultados f\u00edsicos y tangibles (P14). Podr\u00e1s aplicar tu pensamiento pr\u00e1ctico y tu visi\u00f3n innovadora para dise\u00f1ar entornos que impacten positivamente en la vida de las personas, considerando tambi\u00e9n tu inter\u00e9s en el bienestar (P1)."}, {"titulo": "Dise\u00f1o Gr\u00e1fico Publicitario (Universidad C\u00e9sar Vallejo, SENATI)", "descripcion": "Tu inter\u00e9s en dise\u00f1ar afiches y campa\u00f1as publicitarias para redes sociales (P8), junto con tu b\u00fasqueda de soluciones creativas (P3) y tu afinidad por los estudios de dise\u00f1o (P4), hacen de esta opci\u00f3n una excelente elecci\u00f3n. Desarrollar\u00e1s habilidades para comunicar ideas visualmente, lo que tambi\u00e9n te permitir\u00eda aplicar tu esp\u00edritu emprendedor y tu deseo de independencia (P9), creando tu propia marca o agencia en Piura."}, {"titulo": "Ingenier\u00eda Industrial (Universidad Nacional de Piura, Universidad de Piura)", "descripcion": "Esta carrera es ideal para tu perfil pr\u00e1ctico, de acci\u00f3n r\u00e1pida y orientado a la eficiencia (P10, P14). Te permitir\u00e1 explorar tu inter\u00e9s en la tecnolog\u00eda y la innovaci\u00f3n (P2, P6, P12) desde una perspectiva de optimizaci\u00f3n de procesos y sistemas. Tu esp\u00edritu emprendedor (P12) y tu capacidad para proponer mejoras encontrar\u00e1n un campo f\u00e9rtil aqu\u00ed, desarrollando soluciones para empresas locales y nacionales, y tus habilidades de gesti\u00f3n (P7) ser\u00e1n clave."}], "conclusiones": "Matias, tu combinaci\u00f3n de creatividad, habilidad para trabajar con personas, visi\u00f3n tecnol\u00f3gica y esp\u00edritu emprendedor te posiciona para un futuro prometedor. Te animo a investigar a fondo estas opciones, visitar las instituciones en Piura y conversar con profesionales de cada campo. Recuerda que tu camino vocacional es \u00fanico y est\u00e1 lleno de posibilidades para que dejes tu huella en nuestra querida Piura. \u00a1Conf\u00eda en tus talentos!"}', '2026-06-22 14:40:09.258598', NULL);
INSERT INTO public.resultados VALUES ('9b06ddcb-a38a-4c77-8b9b-9673a78c1ee8', 'e01d932e-4a1d-440a-89b2-43162a99fcad', 1, '{"1": "Comunicación, Arte o Historia (Lectura, expresión y sociedad).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Busco una forma creativa, diferente o ''fuera de la caja'' para resolverlo.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El que diseña las diapositivas, hace la carátula y le da el toque visual.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Una cámara profesional, un lienzo o un programa de diseño gráfico.", "8": "Diseñar los afiches y las campañas de publicidad para redes sociales.", "9": "La independencia: tener libertad para expresar mis ideas sin horarios estrictos.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Empezando a armarlo directamente, aprendiendo mediante la práctica y el error.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, RODOLFO FRANCISCO! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y acompa\u00f1arte en este importante camino hacia tu futuro profesional en Piura.", "perfil": "Rodolfo, tus respuestas reflejan un perfil marcadamente inclinado hacia la **tecnolog\u00eda, la innovaci\u00f3n y la resoluci\u00f3n pr\u00e1ctica de problemas**. Demuestras una gran curiosidad por **explorar el mundo digital, los videojuegos, la inteligencia artificial y los lanzamientos de nuevos dispositivos**, as\u00ed como una habilidad innata para **arreglar aparatos y sistemas**. Eres una persona con una mente **creativa, propositiva y orientada a encontrar soluciones ''fuera de la caja''**, siempre buscando la eficiencia. Tu esp\u00edritu **emprendedor** es notable, con una clara ambici\u00f3n de **fundar una startup tecnol\u00f3gica** y aprender **directamente mediante la pr\u00e1ctica y el error**. Adem\u00e1s, te destacas por ser **emp\u00e1tico, comunicativo y disfrutar del trabajo en equipo**, habilidades esenciales para liderar y colaborar en proyectos innovadores.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda de Telecomunicaciones (Universidad Nacional de Piura - UNP / SENATI - Redes y Comunicaciones de Datos)", "descripcion": "Esta carrera es un camino directo para materializar tu inter\u00e9s en las telecomunicaciones, los nuevos celulares, el internet y tu habilidad para arreglar aparatos. Te permitir\u00e1 dise\u00f1ar, implementar y gestionar la infraestructura de comunicaci\u00f3n, lo cual es fundamental para tu sue\u00f1o de fundar una startup tecnol\u00f3gica que revolucione el mercado peruano."}, {"titulo": "Ingenier\u00eda de Sistemas o Ingenier\u00eda de Software (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV / SENATI - Desarrollo de Software)", "descripcion": "Tu fascinaci\u00f3n por explorar la tecnolog\u00eda, la inteligencia artificial, los videojuegos y tu enfoque creativo para resolver problemas te preparan idealmente para esta profesi\u00f3n. Aqu\u00ed podr\u00e1s desarrollar sistemas y software innovadores, lo que se alinea perfectamente con tu ambici\u00f3n de emprender y crear soluciones tecnol\u00f3gicas de impacto."}, {"titulo": "Ingenier\u00eda Electr\u00f3nica (Universidad Nacional de Piura - UNP / SENATI - Electr\u00f3nica Industrial)", "descripcion": "Dada tu inclinaci\u00f3n a ''arreglar cosas en casa'', tu inter\u00e9s en los motores y tu preferencia por el aprendizaje pr\u00e1ctico, la Ingenier\u00eda Electr\u00f3nica es una excelente opci\u00f3n. Esta carrera te permitir\u00eda entender, dise\u00f1ar y construir el hardware que da vida a las telecomunicaciones y otros dispositivos, complementando tu visi\u00f3n de innovaci\u00f3n y desarrollo de aparatos tecnol\u00f3gicos."}], "conclusiones": "Rodolfo, tienes un perfil muy prometedor, con una clara vocaci\u00f3n por la tecnolog\u00eda y la innovaci\u00f3n. Tu proactividad, creatividad y esp\u00edritu emprendedor son tus mayores fortalezas. En Piura, cuentas con excelentes instituciones como la UNP, UDEP, UCV y SENATI, que ofrecen las carreras necesarias para convertir tus sue\u00f1os en realidad. Te animo a seguir explorando estas opciones, visitando sus instalaciones y conversando con profesionales del sector. \u00a1El futuro tecnol\u00f3gico en Piura te espera, y estoy seguro de que tienes el potencial para ser un agente de cambio!"}', '2026-06-22 14:41:39.070849', NULL);
INSERT INTO public.resultados VALUES ('0899dead-8e4f-4f41-81bc-dec2ec434a0a', '29e5ad53-8aeb-457a-9765-4ca8578c35cd', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Busco una forma creativa, diferente o ''fuera de la caja'' para resolverlo.", "4": "En un estudio de diseño, teatro, o viajando constantemente.", "5": "El que diseña las diapositivas, hace la carátula y le da el toque visual.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Diseñar los afiches y las campañas de publicidad para redes sociales.", "9": "El descubrimiento: poder investigar y encontrar verdades o curas.", "10": "Me encantan; prefiero tener instrucciones claras, orden y saber qué esperar.", "11": "Para que les explique tareas difíciles de matemáticas o ciencias.", "12": "Encontrar la cura para una enfermedad compleja.", "13": "Leyendo el manual completo antes de tocar cualquier pieza.", "14": "Soy una persona curiosa, analítica y me gusta llegar al fondo de las cosas."}', '{"saludo": "\u00a1Hola, HADDE JUVITZA!", "perfil": "Hubo un error al procesar tu an\u00e1lisis con la IA: 429 RESOURCE_EXHAUSTED. {''error'': {''code'': 429, ''message'': ''You exceeded your current quota, please check your plan and billing details. For more information on this error, head to: https://ai.google.dev/gemini-api/docs/rate-limits. To monitor your current usage, head to: https://ai.dev/rate-limit. \\n* Quota exceeded for metric: generativelanguage.googleapis.com/generate_content_free_tier_requests, limit: 20, model: gemini-2.5-flash\\nPlease retry in 18.986811114s.'', ''status'': ''RESOURCE_EXHAUSTED'', ''details'': [{''@type'': ''type.googleapis.com/google.rpc.Help'', ''links'': [{''description'': ''Learn more about Gemini API quotas'', ''url'': ''https://ai.google.dev/gemini-api/docs/rate-limits''}]}, {''@type'': ''type.googleapis.com/google.rpc.QuotaFailure'', ''violations'': [{''quotaMetric'': ''generativelanguage.googleapis.com/generate_content_free_tier_requests'', ''quotaId'': ''GenerateRequestsPerDayPerProjectPerModel-FreeTier'', ''quotaDimensions'': {''location'': ''global'', ''model'': ''gemini-2.5-flash''}, ''quotaValue'': ''20''}]}, {''@type'': ''type.googleapis.com/google.rpc.RetryInfo'', ''retryDelay'': ''18s''}]}}", "carreras_sugeridas": [], "conclusiones": "Por favor, intenta realizar el test m\u00e1s tarde."}', '2026-06-22 14:44:40.104445', NULL);
INSERT INTO public.resultados VALUES ('85323958-ef7d-4fff-907d-a28faa581e27', '29e5ad53-8aeb-457a-9765-4ca8578c35cd', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Pido opiniones, converso con mi equipo y buscamos una solución juntos.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El líder que expone, reparte los temas y organiza los tiempos.", "6": "Lanzamientos de nuevos celulares, inteligencia artificial o motores.", "7": "Una cámara profesional, un lienzo o un programa de diseño gráfico.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Diseñar y construir un puente o edificio moderno para tu ciudad.", "13": "Empezando a armarlo directamente, aprendiendo mediante la práctica y el error.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, HADDE JUVITZA!", "perfil": "Hubo un error al procesar tu an\u00e1lisis con la IA: 429 RESOURCE_EXHAUSTED. {''error'': {''code'': 429, ''message'': ''You exceeded your current quota, please check your plan and billing details. For more information on this error, head to: https://ai.google.dev/gemini-api/docs/rate-limits. To monitor your current usage, head to: https://ai.dev/rate-limit. \\n* Quota exceeded for metric: generativelanguage.googleapis.com/generate_content_free_tier_requests, limit: 20, model: gemini-2.5-flash\\nPlease retry in 15.322310269s.'', ''status'': ''RESOURCE_EXHAUSTED'', ''details'': [{''@type'': ''type.googleapis.com/google.rpc.Help'', ''links'': [{''description'': ''Learn more about Gemini API quotas'', ''url'': ''https:/