INSERT INTO public.resultados VALUES ('f59046ce-53c2-4912-8f85-11773633ad08', '29e5ad53-8aeb-457a-9765-4ca8578c35cd', 1, '{"1": "Comunicación, Arte o Historia (Lectura, expresión y sociedad).", "2": "Saliendo con amigos, en actividades grupales o ayudando a otros.", "3": "Tomo el liderazgo, organizo a los demás y tomo decisiones rápidas.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El líder que expone, reparte los temas y organiza los tiempos.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Hojas de cálculo (Excel), agendas de negocios y gráficos financieros.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para que les ayude a organizar un evento, fiesta o vender algo.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Empezando a armarlo directamente, aprendiendo mediante la práctica y el error.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, HADDE JUVITZA! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y acompa\u00f1arte en este importante camino. Tus respuestas revelan un potencial incre\u00edble y una visi\u00f3n clara de lo que buscas.", "perfil": "HADDE, tu perfil se destaca por una combinaci\u00f3n impresionante de habilidades de liderazgo, una fuerte orientaci\u00f3n social y un marcado esp\u00edritu emprendedor. Eres una persona inherentemente comunicativa y emp\u00e1tica, que disfruta trabajar en equipo y siente una profunda conexi\u00f3n con las causas sociales y el bienestar de los dem\u00e1s. No solo te ves liderando, sino que activamente tomas la iniciativa, organizas y tomas decisiones r\u00e1pidas, siempre buscando la eficiencia. Tu ambici\u00f3n por el \u00e9xito econ\u00f3mico y la direcci\u00f3n de proyectos grandes es evidente, y demuestras una gran aptitud para las herramientas de gesti\u00f3n y finanzas. La idea de fundar una startup innovadora que revolucione el mercado peruano, combinada con tu preferencia por el aprendizaje pr\u00e1ctico, muestra que eres una persona de acci\u00f3n, con visi\u00f3n y un deseo genuino de generar un impacto significativo en tu entorno.", "carreras_sugeridas": [{"titulo": "Administraci\u00f3n de Empresas (Universidad Nacional de Piura - UNP, Universidad de Piura - UDEP, Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera es una base s\u00f3lida para tu perfil. Te permitir\u00e1 desarrollar tus habilidades de liderazgo y organizaci\u00f3n, fundamentales para dirigir proyectos grandes y tomar decisiones estrat\u00e9gicas. Aprender\u00e1s sobre finanzas, marketing, recursos humanos y gesti\u00f3n, todo lo cual te preparar\u00e1 para emprender tu propia empresa o liderar en una oficina corporativa, como lo indicaste. La gesti\u00f3n es clave para cualquier startup innovadora."}, {"titulo": "Marketing y Direcci\u00f3n de Empresas (Universidad de Piura - UDEP, Universidad C\u00e9sar Vallejo - UCV) o Ciencias de la Comunicaci\u00f3n con \u00e9nfasis en Marketing (Universidad Nacional de Piura - UNP)", "descripcion": "Tu facilidad para la comunicaci\u00f3n, la organizaci\u00f3n de eventos y tu deseo de ''revolucionar el mercado'' encajan perfectamente con esta \u00e1rea. Aprender\u00e1s a entender a los consumidores, dise\u00f1ar estrategias para vender productos o servicios, y gestionar la imagen de una empresa. Esto es crucial para el \u00e9xito de una startup tecnol\u00f3gica, donde la capacidad de comunicar tu propuesta de valor y posicionarte en el mercado es vital."}, {"titulo": "Ingenier\u00eda Comercial (Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera combina tu inter\u00e9s por el liderazgo, el \u00e9xito econ\u00f3mico y la innovaci\u00f3n. Te proporcionar\u00e1 herramientas para la gesti\u00f3n empresarial, la formulaci\u00f3n de estrategias comerciales y el an\u00e1lisis de mercados, con un enfoque en la optimizaci\u00f3n de procesos y la b\u00fasqueda de nuevas oportunidades. Es ideal para quienes, como t\u00fa, desean dirigir proyectos, fundar negocios innovadores y generar un impacto econ\u00f3mico significativo."}], "conclusiones": "HADDE, tu visi\u00f3n de futuro es clara y tus habilidades son un gran activo. Tienes la inteligencia, la empat\u00eda y la determinaci\u00f3n para alcanzar tus metas. Te animo a investigar a fondo estas opciones en las universidades de nuestra regi\u00f3n Piura, visitar sus campus si es posible, y conversar con profesionales de estos campos. Recuerda que tu camino se construir\u00e1 con cada paso, y lo m\u00e1s importante es que mantengas esa pasi\u00f3n por el liderazgo, la innovaci\u00f3n y el servicio a la sociedad. \u00a1El \u00e9xito te espera en Piura!"}', '2026-06-22 14:49:00.248708', NULL);
INSERT INTO public.resultados VALUES ('f5c92cee-1c8a-4d09-b516-97c372b41934', '4daf95ea-7b61-4040-9a86-70f2c5ee2324', 1, '{"1": "Comunicación, Arte o Historia (Lectura, expresión y sociedad).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Economía, negocios, emprendimientos o política local e internacional.", "7": "Una cámara profesional, un lienzo o un programa de diseño gráfico.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El descubrimiento: poder investigar y encontrar verdades o curas.", "10": "Me encantan; prefiero tener instrucciones claras, orden y saber qué esperar.", "11": "Para pedirme un consejo personal o porque sé escuchar muy bien.", "12": "Escribir un libro o dirigir una película que impacte a millones.", "13": "Viendo un tutorial en video y fijándome en los detalles visuales.", "14": "Soy una persona creativa, original y muy conectada con mis emociones."}', '{"saludo": "\u00a1Hola, SAMIR JESUS! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y ofrecerte algunas ideas para tu futuro en Piura.", "perfil": "Samir, tus respuestas revelan un perfil multifac\u00e9tico y muy interesante. Demuestras una **mente anal\u00edtica y estructurada** (Pregunta 3, 10), con una clara inclinaci\u00f3n hacia la l\u00f3gica, el orden y la resoluci\u00f3n de problemas paso a paso. Te sientes atra\u00eddo por el mundo de los **negocios, la econom\u00eda y el emprendimiento** (Pregunta 4, 6, 8), con un deseo de liderar o dirigir en entornos corporativos o bancarios, y una habilidad para la log\u00edstica y la administraci\u00f3n de recursos. \n\nPor otro lado, posees una **fuerte vena creativa y comunicativa** (Pregunta 1, 7, 12, 13, 14). Te apasiona la expresi\u00f3n a trav\u00e9s del arte, la escritura, la direcci\u00f3n audiovisual y el dise\u00f1o, y eres un aprendiz visual con gran atenci\u00f3n al detalle. Eres una persona **emp\u00e1tica y conciliadora** (Pregunta 5, 11), con una gran capacidad para escuchar y ofrecer consejo, lo que te convierte en un l\u00edder natural que busca la armon\u00eda y el entendimiento. Tu inter\u00e9s en la investigaci\u00f3n y el descubrimiento (Pregunta 9) complementa tu deseo de encontrar verdades y estructurar soluciones. Aunque tambi\u00e9n muestras inter\u00e9s en explorar tecnolog\u00eda y arreglar cosas (Pregunta 2), este aspecto parece integrarse m\u00e1s con tu capacidad para comprender sistemas y optimizar procesos dentro de tus otros intereses, en lugar de ser un inter\u00e9s puramente t\u00e9cnico de desarrollo de software.", "carreras_sugeridas": [{"titulo": "Administraci\u00f3n de Empresas (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP)", "descripcion": "Esta carrera es ideal para tu perfil anal\u00edtico, l\u00f3gico y estructurado (P3, P10), y tu atracci\u00f3n por el mundo corporativo, los negocios y el emprendimiento (P4, P6, P8). Te permitir\u00e1 desarrollar habilidades en gesti\u00f3n, finanzas y log\u00edstica, donde tu deseo de orden y tu capacidad para administrar recursos ser\u00e1n clave. Adem\u00e1s, tu liderazgo conciliador (P5) y tus habilidades comunicativas (P1, P11) te convertir\u00e1n en un excelente gestor de equipos y proyectos."}, {"titulo": "Marketing y Publicidad (Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta opci\u00f3n fusiona tu inter\u00e9s por los negocios y el emprendimiento (P4, P6) con tu marcada creatividad y pasi\u00f3n por la comunicaci\u00f3n visual y la expresi\u00f3n (P1, P7, P12, P13, P14). Podr\u00e1s aplicar tu mente anal\u00edtica (P3) para entender el mercado y desarrollar estrategias, mientras utilizas tu originalidad para crear campa\u00f1as que impacten a millones. Tu capacidad para escuchar (P11) te ayudar\u00e1 a conectar con las necesidades del p\u00fablico y tu inter\u00e9s por la investigaci\u00f3n (P9) ser\u00e1 valioso para el an\u00e1lisis de tendencias."}, {"titulo": "Ciencias de la Comunicaci\u00f3n (Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Si tu vocaci\u00f3n por la comunicaci\u00f3n, el arte, la historia, la escritura y la direcci\u00f3n de proyectos audiovisuales (P1, P7, P12, P14) es muy fuerte, esta carrera te permitir\u00e1 explorar a fondo esas pasiones. Tu mente estructurada (P3), tu capacidad para la log\u00edstica y la administraci\u00f3n (P8), y tu inter\u00e9s en la investigaci\u00f3n (P9) ser\u00e1n muy valiosos para la producci\u00f3n de contenidos, la gesti\u00f3n de medios o la comunicaci\u00f3n estrat\u00e9gica, donde la creatividad y el impacto son fundamentales."}], "conclusiones": "Samir, tienes un potencial enorme debido a la riqueza y diversidad de tus intereses. La clave est\u00e1 en encontrar una carrera donde puedas integrar tu mente l\u00f3gica y empresarial con tu esp\u00edritu creativo y comunicativo. Te animo a investigar a fondo cada una de estas opciones en las universidades de Piura, visitar sus campus si es posible, y conversar con profesionales de estos campos. Recuerda que tu camino es \u00fanico y est\u00e1 lleno de oportunidades para crecer y dejar tu huella en nuestra regi\u00f3n. \u00a1Mucho \u00e9xito en tu proceso de decisi\u00f3n!"}', '2026-06-22 15:17:02.351377', NULL);
INSERT INTO public.resultados VALUES ('46e0a35c-ee9b-4a02-882c-d43283a57e69', '775f78e4-3ed2-405e-a605-f36db224f829', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El que investiga a fondo, recopila la información y revisa que todo tenga sentido.", "6": "Descubrimientos científicos, avances médicos o documentales de naturaleza.", "7": "Un microscopio, instrumentos de medición o software de datos.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El descubrimiento: poder investigar y encontrar verdades o curas.", "10": "Me encantan; prefiero tener instrucciones claras, orden y saber qué esperar.", "11": "Para que les explique tareas difíciles de matemáticas o ciencias.", "12": "Encontrar la cura para una enfermedad compleja.", "13": "Leyendo el manual completo antes de tocar cualquier pieza.", "14": "Soy una persona curiosa, analítica y me gusta llegar al fondo de las cosas."}', '{"saludo": "\u00a1Hola, VIVIANA ROSANNE!", "perfil": "Hubo un error al procesar tu an\u00e1lisis con la IA: 429 RESOURCE_EXHAUSTED. {''error'': {''code'': 429, ''message'': ''You exceeded your current quota, please check your plan and billing details. For more information on this error, head to: https://ai.google.dev/gemini-api/docs/rate-limits. To monitor your current usage, head to: https://ai.dev/rate-limit. \\n* Quota exceeded for metric: generativelanguage.googleapis.com/generate_content_free_tier_requests, limit: 20, model: gemini-2.5-flash\\nPlease retry in 28.64255677s.'', ''status'': ''RESOURCE_EXHAUSTED'', ''details'': [{''@type'': ''type.googleapis.com/google.rpc.Help'', ''links'': [{''description'': ''Learn more about Gemini API quotas'', ''url'': ''https://ai.google.dev/gemini-api/docs/rate-limits''}]}, {