INSERT INTO public.resultados VALUES ('23784bfc-d447-4704-8ba2-f22b160a7115', '775f78e4-3ed2-405e-a605-f36db224f829', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Analizo los datos, busco la lógica y estructuro una solución paso a paso.", "4": "En un laboratorio, clinic o centro de investigación.", "5": "El que investiga a fondo, recopila la información y revisa que todo tenga sentido.", "6": "Descubrimientos científicos, avances médicos o documentales de naturaleza.", "7": "Un microscopio, instrumentos de medición o software de datos.", "8": "Ayudar en la logística, administrando las donaciones y el presupuesto.", "9": "El descubrimiento: poder investigar y encontrar verdades o curas.", "10": "Me encantan; prefiero tener instrucciones claras, orden y saber qué esperar.", "11": "Para que les explique tareas difíciles de matemáticas o ciencias.", "12": "Encontrar la cura para una enfermedad compleja.", "13": "Leyendo el manual completo antes de tocar cualquier pieza.", "14": "Soy una persona curiosa, analítica y me gusta llegar al fondo de las cosas."}', '{"saludo": "\u00a1Hola, VIVIANA ROSANNE!", "perfil": "Hubo un error al procesar tu an\u00e1lisis con la IA: 429 RESOURCE_EXHAUSTED. {''error'': {''code'': 429, ''message'': ''You exceeded your current quota, please check your plan and billing details. For more information on this error, head to: https://ai.google.dev/gemini-api/docs/rate-limits. To monitor your current usage, head to: https://ai.dev/rate-limit. \\n* Quota exceeded for metric: generativelanguage.googleapis.com/generate_content_free_tier_requests, limit: 20, model: gemini-2.5-flash\\nPlease retry in 41.252749615s.'', ''status'': ''RESOURCE_EXHAUSTED'', ''details'': [{''@type'': ''type.googleapis.com/google.rpc.Help'', ''links'': [{''description'': ''Learn more about Gemini API quotas'', ''url'': ''https://ai.google.dev/gemini-api/docs/rate-limits''}]}, {''@type'': ''type.googleapis.com/google.rpc.QuotaFailure'', ''violations'': [{''quotaMetric'': ''generativelanguage.googleapis.com/generate_content_free_tier_requests'', ''quotaId'': ''GenerateRequestsPerDayPerProjectPerModel-FreeTier'', ''quotaDimensions'': {''location'': ''global'', ''model'': ''gemini-2.5-flash''}, ''quotaValue'': ''20''}]}, {''@type'': ''type.googleapis.com/google.rpc.RetryInfo'', ''retryDelay'': ''41s''}]}}", "carreras_sugeridas": [], "conclusiones": "Por favor, intenta realizar el test m\u00e1s tarde."}', '2026-06-22 15:20:17.680383', NULL);
INSERT INTO public.resultados VALUES ('04e552f6-81ab-4806-a5c7-2b884d02e7bc', '94e70a27-2216-4d76-9449-d282ade38677', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Investigando temas nuevos, leyendo o armando estrategias.", "3": "Tomo el liderazgo, organizo a los demás y tomo decisiones rápidas.", "4": "En una oficina corporativa, banco o dirigiendo tu propia empresa.", "5": "El que diseña las diapositivas, hace la carátula y le da el toque visual.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Hojas de cálculo (Excel), agendas de negocios y gráficos financieros.", "8": "Ir al campo a construir casas, limpiar playas o plantar árboles.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Las sigo si son lógicas, pero si encuentro una forma más eficiente, la propongo.", "11": "Para que les arregle la computadora, el internet o algún aparato.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Viendo un tutorial en video y fijándome en los detalles visuales.", "14": "Soy una persona práctica, de acción rápida y me gusta ver resultados físicos."}', '{"saludo": "\u00a1Hola, PAULITA ANALIA! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y ofrecerte algunas recomendaciones para tu futuro. Tu test revela una personalidad muy din\u00e1mica y con muchas fortalezas. \u00a1Vamos a explorarlas juntos!", "perfil": "PAULITA, tus respuestas dibujan el perfil de una l\u00edder nata con una mente anal\u00edtica y estrat\u00e9gica. Te sientes c\u00f3moda con las ciencias exactas, el c\u00e1lculo y la f\u00edsica, y disfrutas investigando, armando estrategias y tomando decisiones r\u00e1pidas. Tu deseo de liderar y organizar, sumado a tu aspiraci\u00f3n de trabajar en un entorno corporativo, un banco o dirigir tu propia empresa, muestra un claro inter\u00e9s por el mundo de los negocios y la gesti\u00f3n. Eres una persona pr\u00e1ctica, de acci\u00f3n r\u00e1pida, que busca la eficiencia y ver resultados tangibles, lo cual se alinea con tu inter\u00e9s en construir y mejorar tu comunidad. Adem\u00e1s, tienes una inclinaci\u00f3n por la tecnolog\u00eda y un esp\u00edritu emprendedor, so\u00f1ando con fundar una startup que genere impacto. Tu atenci\u00f3n a los detalles visuales y tu forma de aprender tambi\u00e9n son puntos clave.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda Industrial (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP)", "descripcion": "Esta carrera es ideal para ti, Paulita. Combina tu afinidad por las matem\u00e1ticas y las ciencias exactas (Pregunta 1), tu capacidad para investigar y armar estrategias (Pregunta 2), tu liderazgo y toma de decisiones (Pregunta 3), y tu b\u00fasqueda de eficiencia (Pregunta 10). Te preparar\u00eda para optimizar procesos en empresas, bancos o incluso tu propia startup, logrando resultados f\u00edsicos y mejorando la comunidad (Preguntas 4, 7, 9 y 14)."}, {"titulo": "Administraci\u00f3n de Empresas / Econom\u00eda (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Si tu visi\u00f3n es dirigir tu propia empresa o trabajar en el sector financiero, esta es una excelente opci\u00f3n. Se alinea perfectamente con tu deseo de estar en una oficina corporativa o un banco (Pregunta 4), tu manejo de hojas de c\u00e1lculo y gr\u00e1ficos financieros (Pregunta 7), tu liderazgo (Pregunta 3) y tu esp\u00edritu emprendedor de fundar una startup (Pregunta 12). Te permitir\u00e1 desarrollar estrategias y ver resultados directamente en el mercado (Preguntas 2, 10 y 14)."}, {"titulo": "Ingenier\u00eda de Sistemas / Software (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP)", "descripcion": "Tu inter\u00e9s en la tecnolog\u00eda, especialmente en ''arreglar la computadora o el internet'' (Pregunta 11) y tu sue\u00f1o de ''fundar una startup tecnol\u00f3gica que revolucione el mercado peruano'' (Pregunta 12), te llevar\u00edan muy bien por este camino. Aqu\u00ed aplicar\u00edas tus habilidades en ciencias exactas (Pregunta 1), tu capacidad de investigaci\u00f3n y estrategia (Pregunta 2), y tu enfoque en la eficiencia (Pregunta 10), creando soluciones innovadoras con un impacto tangible."}], "conclusiones": "Paulita, tienes un perfil muy completo y prometedor, con una clara orientaci\u00f3n al liderazgo, la resoluci\u00f3n de problemas y la creaci\u00f3n de impacto. Las opciones que te he presentado aprovechan al m\u00e1ximo tus habilidades anal\u00edticas, tu visi\u00f3n emprendedora y tu deseo de contribuir. Te animo a investigar m\u00e1s sobre estas carreras en las universidades de Piura, hablar con profesionales de estos campos y seguir cultivando esa pasi\u00f3n por la eficiencia y la innovaci\u00f3n. \u00a1El futuro est\u00e1 en tus manos y tienes todo para alcanzar grandes logros aqu\u00ed en nuestra Piura!"}', '2026-06-22 17:20:24.692534', NULL);
INSERT INTO public.resultados VALUES ('427cb9e2-77d3-42e5-a797-0893a0bca39a', 'ea9addc0-0d82-43cf-a189-e993b2d89790', 1, '{"1": "Computación, Robótica o Talleres técnicos (Crear y armar cosas).", "2": "Saliendo con amigos, en actividades grupales o ayudando a otros.", "3": "Pido opiniones, converso con mi equipo y buscamos una solución juntos.", "4": "En un estudio de diseño, teatro, o viajando constantemente.", "5": "El que diseña las diapositivas, hace la carátula y le da el toque visual.", "6": "Economía, negocios, emprendimientos o política local e internacional.", "7": "Una cámara profesional, un lienzo o un programa de diseño gráfico.", "8": "Diseñar los afiches y las campañas de publicidad para redes sociales.", "9": "El liderazgo y éxito económico: dirigir proyectos grandes y ganar bien.", "10": "Me frustran un poco; prefiero la flexibilidad y hacer las cosas a mi modo.", "11": "Para pedirme un consejo personal o porque sé escuchar muy bien.", "12": "Fundar una startup tecnológica que revolucione el mercado peruano.", "13": "Viendo un tutorial en video y fijándome en los detalles visuales.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, Elien Dayana! Es un gusto para m\u00ed, como orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y acompa\u00f1arte en esta importante etapa.", "perfil": "Elien, tu perfil es el de una persona claramente **creativa y con una fuerte inclinaci\u00f3n visual**, lo cual se evidencia en tu gusto por dise\u00f1ar diapositivas, hacer car\u00e1tulas y dar un toque est\u00e9tico a todo lo que haces (Pregunta 5). Disfrutas de las herramientas de dise\u00f1o gr\u00e1fico, las c\u00e1maras profesionales y los lienzos (Pregunta 7), y aprendes mejor fij\u00e1ndote en los detalles visuales (Pregunta 13). Tienes un inter\u00e9s muy marcado en el **dise\u00f1o aplicado a la comunicaci\u00f3n y la publicidad**, especialmente en la creaci\u00f3n de afiches y campa\u00f1as para redes sociales (Pregunta 8). \n\nAdem\u00e1s de tu faceta art\u00edstica, demuestras un gran **esp\u00edritu emprendedor y de liderazgo**. Te interesan la econom\u00eda, los negocios y los emprendimientos (Pregunta 6), y aspiras al liderazgo y al \u00e9xito econ\u00f3mico, dirigiendo proyectos grandes (Pregunta 9). \u00a1Incluso sue\u00f1as con fundar una startup tecnol\u00f3gica que revolucione el mercado peruano! (Pregunta 12). \n\nEres una persona muy **sociable, emp\u00e1tica y colaborativa**. Disfrutas de las actividades grupales, ayudando a otros (Pregunta 2), y eres valorada por tu capacidad de escuchar y dar consejos personales (Pregunta 11, Pregunta 14). Cuando enfrentas desaf\u00edos, buscas soluciones en equipo, pidiendo opiniones y conversando (Pregunta 3). Prefieres la flexibilidad y hacer las cosas a tu modo (Pregunta 10), lo que sugiere que te sentir\u00edas c\u00f3moda en entornos din\u00e1micos como un estudio de dise\u00f1o o incluso viajando (Pregunta 4). Tu inter\u00e9s por la computaci\u00f3n y la rob\u00f3tica (Pregunta 1) complementa tu visi\u00f3n de crear y armar cosas, d\u00e1ndote una base para la innovaci\u00f3n tecnol\u00f3gica.\n\nEn resumen, Elien, eres una visionaria con talento para el dise\u00f1o, habilidades sociales destacadas y una clara ambici\u00f3n por emprender y liderar.", "carreras_sugeridas": [{"titulo": "Dise\u00f1o Gr\u00e1fico Digital o Publicitario (SENATI / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta carrera encaja perfectamente con tu deseo expl\u00edcito de ser una gran dise\u00f1adora y tus respuestas que enfatizan el dise\u00f1o visual (Preguntas 5, 7, 13). Aprender\u00e1s a crear afiches, campa\u00f1as publicitarias y todo tipo de contenido visual para diversas plataformas, incluyendo redes sociales (Pregunta 8). Adem\u00e1s, te brindar\u00e1 las herramientas para materializar tu inter\u00e9s en la computaci\u00f3n y la creaci\u00f3n digital (Pregunta 1), y la flexibilidad que tanto valoras (Pregunta 10)."}, {"titulo": "Ciencias de la Comunicaci\u00f3n con Menci\u00f3n en Marketing y Publicidad (Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Esta opci\u00f3n potencia tu habilidad para el dise\u00f1o y la comunicaci\u00f3n, permiti\u00e9ndote aplicar tu creatividad en la conceptualizaci\u00f3n y ejecuci\u00f3n de campa\u00f1as (Pregunta 8). Tus dotes comunicativas, tu empat\u00eda y tu gusto por el trabajo en equipo (Preguntas 2, 3, 11, 14) ser\u00e1n fundamentales. Adem\u00e1s, te dar\u00e1 una base s\u00f3lida en negocios y emprendimientos (Pregunta 6), prepar\u00e1ndote para liderar proyectos y, qui\u00e9n sabe, para esa startup tecnol\u00f3gica que sue\u00f1as fundar (Pregunta 9, 12)."}, {"titulo": "Administraci\u00f3n de Empresas con \u00c9nfasis en Emprendimiento (Universidad Nacional de Piura - UNP / Universidad de Piura - UDEP / Universidad C\u00e9sar Vallejo - UCV)", "descripcion": "Si bien no es directamente de dise\u00f1o, esta carrera es ideal para desarrollar tu liderazgo, tu visi\u00f3n de negocios y tu esp\u00edritu emprendedor (Preguntas 6, 9, 12). Te proporcionar\u00e1 las herramientas para gestionar proyectos grandes y, sobre todo, para fundar y dirigir tu propia empresa o startup tecnol\u00f3gica (Pregunta 12). Podr\u00edas combinar esta formaci\u00f3n con cursos cortos o especializaciones en dise\u00f1o gr\u00e1fico para fusionar tu visi\u00f3n creativa con una s\u00f3lida base empresarial, d\u00e1ndote la autonom\u00eda y flexibilidad que buscas (Pregunta 10)."}], "conclusiones": "Elien Dayana, tienes un futuro brillante por delante, especialmente en el campo del dise\u00f1o y el emprendimiento. Tu pasi\u00f3n por la creatividad, tu habilidad para comunicarte y trabajar en equipo, y tu ambici\u00f3n por liderar y generar impacto son cualidades muy valiosas. Te animo a investigar estas carreras en las instituciones de nuestra regi\u00f3n Piura, visitar sus campus, conversar con estudiantes y docentes. \u00a1Con tu talento y determinaci\u00f3n, estamos seguros de que alcanzar\u00e1s tu sue\u00f1o de ser una gran dise\u00f1adora y mucho m\u00e1s!"}', '2026-06-28 12:49:32.091963', NULL);
INSERT INTO public.resultados VALUES ('3da2e23d-5ac0-445a-894b-37ef68105439', '1f6467ee-45f8-42ba-84e6-74e0db536450', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Jugando videojuegos, explorando tecnología o arreglando cosas en casa.", "3": "Pido opiniones, converso con mi equipo y buscamos una solución juntos.", "4": "En campo, construcciones, plantas industriales o al aire libre.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Me adapto fácilmente si eso ayuda a que el grupo funcione mejor.", "11": "Para que les ayude a organizar un evento, fiesta o vender algo.", "12": "Diseñar y construir un puente o edificio moderno para tu ciudad.", "13": "Pidiéndole a alguien que ya sepa que me explique paso a paso.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, jhon! Es un gusto para m\u00ed, como tu orientador vocacional de la I.E. Leonor Cerna de Valdiviezo, analizar tu perfil y acompa\u00f1arte en este importante camino hacia tu futuro en nuestra querida Piura.", "perfil": "Bas\u00e1ndonos estrictamente en tus respuestas, jhon, tu perfil destaca por una fuerte inclinaci\u00f3n hacia las ciencias exactas como las matem\u00e1ticas y la f\u00edsica, lo que sugiere una mente anal\u00edtica y estructurada. Muestras un claro inter\u00e9s por el trabajo pr\u00e1ctico y tangible, disfrutando de actividades como explorar c\u00f3mo funcionan las cosas, usar herramientas y trabajar en ambientes como construcciones o plantas industriales. Eres una persona inherentemente colaborativa, emp\u00e1tica y comunicativa, que valora el trabajo en equipo, busca soluciones consensuadas y se adapta para el bien com\u00fan. Adem\u00e1s, tu deseo de que tu trabajo mejore la vida de tu comunidad y tu inter\u00e9s en dise\u00f1ar y construir infraestructuras revelan una vocaci\u00f3n de servicio y un anhelo por dejar una huella positiva y duradera.", "carreras_sugeridas": [{"titulo": "Ingenier\u00eda Civil (Universidad Nacional de Piura / Universidad de Piura / Universidad C\u00e9sar Vallejo)", "descripcion": "Tu marcado inter\u00e9s por las matem\u00e1ticas, la f\u00edsica y el dise\u00f1o de infraestructuras como puentes y edificios, junto con tu preferencia por el trabajo en campo y en construcciones, te hacen un excelente candidato para esta carrera. Podr\u00e1s aplicar tus conocimientos exactos para crear proyectos que mejoren directamente la vida de tu comunidad."}, {"titulo": "Ingenier\u00eda Industrial (Universidad Nacional de Piura / Universidad de Piura / Universidad C\u00e9sar Vallejo)", "descripcion": "Tu habilidad para el c\u00e1lculo y las ciencias exactas, combinada con tu facilidad para trabajar en equipo, organizar y mejorar procesos en entornos industriales, te permitir\u00e1 optimizar sistemas de producci\u00f3n y gesti\u00f3n. Tu adaptabilidad y rol conciliador ser\u00e1n muy valiosos para liderar equipos y contribuir al desarrollo productivo de la regi\u00f3n."}, {"titulo": "Mecatr\u00f3nica Industrial / Mantenimiento de Maquinaria Pesada (SENATI)", "descripcion": "Si disfrutas ''arreglar cosas'', explorar c\u00f3mo funciona la maquinaria y trabajar con herramientas en talleres o plantas industriales, esta opci\u00f3n t\u00e9cnica es ideal. Te permitir\u00e1 aplicar tus habilidades manuales y tu inter\u00e9s por la tecnolog\u00eda para mantener sistemas complejos en funcionamiento, con un aprendizaje pr\u00e1ctico y paso a paso, muy valorado en el sector productivo de Piura."}], "conclusiones": "jhon, tienes un perfil muy prometedor, con una s\u00f3lida base en ciencias exactas y una clara vocaci\u00f3n pr\u00e1ctica y de servicio a la comunidad. Las instituciones de Piura como la Universidad Nacional de Piura, la Universidad de Piura, la Universidad C\u00e9sar Vallejo y SENATI ofrecen excelentes programas que se alinean perfectamente con tus intereses. Te animo a explorar estas opciones, conversar con profesionales de estos campos y visitar las instituciones. \u00a1Tu futuro en Piura est\u00e1 lleno de oportunidades para construir y mejorar!"}', '2026-06-28 12:58:07.463085', NULL);
INSERT INTO public.resultados VALUES ('8afd25e0-2c24-4301-a950-d49cf16e3f49', '94e70a27-2216-4d76-9449-d282ade38677', 1, '{"1": "Matemáticas, Física o Química (Cálculo y ciencias exactas).", "2": "Dibujando, tocando un instrumento, escribiendo o creando contenido.", "3": "Tomo el liderazgo, organizo a los demás y tomo decisiones rápidas.", "4": "En campo, construcciones, plantas industriales o al aire libre.", "5": "El conciliador que ayuda a los compañeros que no entienden y mantiene la paz.", "6": "Temas de salud mental, derechos humanos, o causas sociales.", "7": "Manuales de maquinaria, planos arquitectónicos o herramientas de taller.", "8": "Dar clases de refuerzo a niños o asistir a adultos mayores.", "9": "El servicio: sentir que mi trabajo mejora la vida de mi comunidad.", "10": "Me adapto fácilmente si eso ayuda a que el grupo funcione mejor.", "11": "Para que les ayude a organizar un evento, fiesta o vender algo.", "12": "Diseñar y construir un puente o edificio moderno para tu ciudad.", "13": "Pidiéndole a alguien que ya sepa que me explique paso a paso.", "14": "Soy una persona empática, comunicativa y disfruto trabajar en equipo."}', '{"saludo": "\u00a1Hola, PAULITA ANALIA!", "perfil": "Hubo un error al procesar tu an\u00e1lisis con la IA: 503 UNAVAILABLE. {''error'': {''code'': 503, ''message'': ''This model is currently experiencing high demand. Spikes in demand are usually temporary. Please try again later.'', ''status'': ''UNAVAILABLE''}}", "carreras_sugeridas": [], "conclusiones": "Por favor, intenta realizar el test m\u00e1s tarde."}', '2026-06-28 15:09:58.480676', NULL);


